INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('07-phu-luc',1,7,'PHỤ LỤC - TỔNG HỢP MẪU BIỂU','Phu luc tong hop cac mau bieu',7,'draft','2026-06-20T11:04:46Z','2026-06-20T11:04:46Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('acab9acf-e8db-4d5b-86c2-9fc94fc9d58b','07-phu-luc',NULL,2,'Điểm bẩy quản trị - Yếu tố định hình tương lai ngành Nha khoa','iem-bay-quan-tri-yeu-to-inh-hinh-tuong-lai-nganh-nha-khoa',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e554ef3c-97a9-474b-8d05-a6619f3b655c','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',0,'text','Trong kỷ nguyên trước, công thức thành công của một phòng khám nha khoa vô cùng đơn giản:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c0677c8-159d-4787-a31d-4c306653618c','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',1,'text','**Bác sĩ có tay nghề giỏi + Vị trí đắc địa = Phòng khám đông khách**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b3f0198-78bd-449a-a887-0f8deab36e0f','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',2,'text','Tuy nhiên, cuộc chơi hiện tại và tương lai đã thay đổi hoàn toàn quy luật. Sự bùng nổ của các chuỗi nha khoa lớn, sự chuyên nghiệp hóa của các quỹ đầu tư và sự thông thái ngày càng cao của khách hàng đã đẩy ngành nha khoa vào một giai đoạn cạnh tranh khốc liệt hơn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8feb14d-0784-4f6f-81c0-5f2a144938f1','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',3,'text','Giai đoạn cạnh tranh bằng **năng lực quản trị hệ thống**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8909bb4c-9a6d-4df1-919d-e8b7b67a2d36','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',4,'text','Quản trị không còn là "việc giấy tờ" của bộ phận hành chính, mà là điểm bẩy chiến lược quyết định sự sinh tồn của phòng khám vì những lý do sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('51fe1cd4-9a89-4010-9f21-31782bce0e14','07-phu-luc','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',4,'Sự dịch chuyển từ "Phụ thuộc cá nhân" sang "Vận hành hệ thống":','su-dich-chuyen-tu-phu-thuoc-ca-nhan-sang-van-hanh-he-thong',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef0d3d24-b417-46f7-8bdd-c2ff4aecdafb','51fe1cd4-9a89-4010-9f21-31782bce0e14',5,'text','Mô hình cũ dựa vào uy tín độc quyền của Bác sĩ chủ (Founder-led) sẽ nhanh chóng chạm trần sinh trưởng. Khi một bác sĩ bận rộn cả ngày tại ghế nha, họ không còn thời gian để tối ưu hóa trải nghiệm khách hàng, quản trị dòng tiền hay đào tạo đội ngũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3e5ba0e-6ae2-431a-957f-9cd05ffaec5b','51fe1cd4-9a89-4010-9f21-31782bce0e14',6,'text','Quản trị hệ thống là lời giải duy nhất để tách rời năng lực của phòng khám ra khỏi thời gian làm việc của một cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('87c50969-3f23-426b-ac23-9511e9b430ee','07-phu-luc','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',4,'Sự phân hóa chuỗi giá trị và trải nghiệm khách hàng:','su-phan-hoa-chuoi-gia-tri-va-trai-nghiem-khach-hang',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8c668ba-eec9-4abd-a338-887a139cca93','87c50969-3f23-426b-ac23-9511e9b430ee',7,'text','Khách hàng không chỉ mua "một chiếc răng Implant chuẩn y khoa", họ mua cả hành trình trải nghiệm từ lúc nhìn thấy bài quảng cáo đầu tiên, sự đón tiếp của lễ tân, cho đến quy trình chăm sóc nhắc lịch hẹn hậu phẫu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4befc7be-a01a-4ecb-9042-4d44a26a1160','87c50969-3f23-426b-ac23-9511e9b430ee',8,'text','Nếu thiếu một mô hình quản trị kết nối mượt mà các điểm chạm này, phòng khám sẽ liên tục rơi vào trạng thái "đầu voi đuôi chuột" marketing rất hay nhưng trải nghiệm thực tế tại phòng khám lại rất tệ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('117de286-f932-4631-ba02-b5fa99aeb3fb','07-phu-luc','acab9acf-e8db-4d5b-86c2-9fc94fc9d58b',4,'Năng lực nhân bản hệ thống (Clinic Replication):','nang-luc-nhan-ban-he-thong-clinic-replication',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3cf82ed8-32c0-4448-b466-3524b42b7d6b','117de286-f932-4631-ba02-b5fa99aeb3fb',9,'text','Khát vọng mở rộng quy mô thành một chuỗi hay một "đế chế" nha khoa sẽ mãi là một giấc mơ xa vời nếu phòng khám đầu tiên vẫn vận hành bằng các mệnh lệnh cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2fec4787-b597-4374-9600-cd8c6d9e3120','117de286-f932-4631-ba02-b5fa99aeb3fb',10,'text','Quản trị chuẩn hóa chính là bước "đóng gói mã gen (DNA)" để sẵn sàng nhân bản mà không làm loãng chất lượng dịch vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e4cc397-23a6-4e6e-8238-34f9bae8671a','117de286-f932-4631-ba02-b5fa99aeb3fb',11,'image',NULL,'book/07-phu-luc/16a3365b-af17-4452-a6fa-e56cd27b69c1-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('64c45599-2e16-4fbf-82bf-479aada34065','07-phu-luc',NULL,2,'BANI, TUNA, HAI - Khi cấu trúc kim tự tháp cũ lỗi thời trước biến động','bani-tuna-hai-khi-cau-truc-kim-tu-thap-cu-loi-thoi-truoc-bien-ong',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04f32265-fa70-4a89-a1eb-99a749c98bef','64c45599-2e16-4fbf-82bf-479aada34065',12,'text','Thế giới kinh doanh hiện tại không còn vận hành theo những đường thẳng tuyến tính dễ dự đoán. Doanh nghiệp của bạn đang phải chèo lái giữa một bối cảnh toàn cầu đầy rẫy biến động qua các mô hình định nghĩa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f6f3b557-f725-4006-9e50-a4e0534b6749','64c45599-2e16-4fbf-82bf-479aada34065',13,'image',NULL,'book/07-phu-luc/92ce2888-486c-4492-a2c8-a7920e7612e0-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8f33a9f-2bad-4b14-a38a-d12570227572','64c45599-2e16-4fbf-82bf-479aada34065',14,'text','Trước những làn sóng này, **Mô hình quản trị Kim tự tháp truyền thống** bộc lộ những điểm yếu chết người: **Quá chậm và quá cứng nhắc**. Khi thông tin phải chạy từ nhân viên cấp dưới, qua 3 cấp quản lý trung gian để lên đến phòng Founder duyệt, thì cơ hội thị trường đã trôi qua, hoặc một khủng hoảng truyền thông nhỏ đã kịp bùng phát thành thảm họa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4d07ed3-311f-4fd8-a2a4-8b99548f5ef9','64c45599-2e16-4fbf-82bf-479aada34065',15,'text','Thế giới này đòi hỏi một mô hình quản trị có các phẩm chất hoàn toàn mới:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff10e801-4bac-4427-8dfe-f559cc869c7a','64c45599-2e16-4fbf-82bf-479aada34065',16,'text','- Chống chọi sự** "Dễ gãy" (Brittle)** bằng tính** Phi tập trung:** Quyền lực và năng lực quyết định phải được phân rã về các đơn vị nhỏ nhất sát sườn với thực tế vận hành. Nếu một mắt xích bị tổn thương, toàn bộ hệ thống vẫn có khả năng đứng vững.  - Hóa giải sự **"Lo âu" (Anxious)** bằng** Thông tin đối xứng:** Nhân sự cần được giải phóng khỏi nỗi sợ sai bằng các ranh giới quyền hạn (Domain) và luật chơi minh bạch. Họ biết rõ mình có quyền làm gì mà không cần chờ sếp gật đầu.  - Thích ứng sự **"Phi tuyến" (Non-linear)** bằng** Tốc độ phản hồi nhanh:** Mô hình không dựa vào những kế hoạch 5 năm xơ cứng, mà dựa vào khả năng phát hiện các điểm nghẽn (Tensions) hằng ngày và liên tục đưa ra các điều chỉnh tức thì.  - Tích hợp **Người - AI (HAI)** bằng** Tư duy Vai trò (Role):** AI đang tái định nghĩa lại năng suất làm việc. Một mô hình quản trị hiện đại phải cho phép gán các công cụ AI vào các vai trò cụ thể trong quy trình một cách linh hoạt, thay vì giữ nguyên các chức danh đóng đinh truyền thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('71a627a4-a4d0-4cfd-9f44-fcbdc5de0d6a','07-phu-luc',NULL,2,'Xu hướng quản trị hiện tại và tương lai: Kỷ nguyên của những mạng lưới tự chủ','xu-huong-quan-tri-hien-tai-va-tuong-lai-ky-nguyen-cua-nhung-mang-luoi-tu-chu',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4755c439-5ffc-4d7d-af0d-34d3ae19f88d','71a627a4-a4d0-4cfd-9f44-fcbdc5de0d6a',17,'text','Xu hướng quản trị toàn cầu đang dịch chuyển mạnh mẽ từ mô hình **Cơ giới (Mechanical Organism)** sang mô hình **Sinh học (Biological Organism)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15dd2666-6dc6-4e29-824b-a0d457007114','71a627a4-a4d0-4cfd-9f44-fcbdc5de0d6a',18,'image',NULL,'book/07-phu-luc/1d19137d-f0e3-4cd2-bf5d-07168dcfb4b1-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b602602-c90c-4f6a-a4a4-acb6bbe1f5e0','07-phu-luc','71a627a4-a4d0-4cfd-9f44-fcbdc5de0d6a',3,'Từ "Quản lý con người" sang "Quản lý hệ thống bằng Vai trò":','tu-quan-ly-con-nguoi-sang-quan-ly-he-thong-bang-vai-tro',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7c7b685-0c4c-4c73-bf02-c41baf6e4bb0','3b602602-c90c-4f6a-a4a4-acb6bbe1f5e0',19,'text','Xu hướng tương lai không còn đi theo hướng** "ai quản lý ai"**, mà là** "hệ thống quy tắc này bảo vệ vai trò nào"**. Con người không còn bị giới hạn bởi một chức danh xơ cứng, họ có thể sở hữu nhiều vai trò khác nhau dựa trên năng lực và sở thích, giúp tối ưu hóa tối đa nguồn lực nội tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('77958b5c-6112-4e5a-bb1f-adf94922f648','3b602602-c90c-4f6a-a4a4-acb6bbe1f5e0',20,'image',NULL,'book/07-phu-luc/9bd026db-bb9a-4e57-81cb-260b33a998eb-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0cee2bc0-9423-4da5-8432-600c34ec2482','07-phu-luc','71a627a4-a4d0-4cfd-9f44-fcbdc5de0d6a',3,'Vận hành bằng "Đồng thuận" (Consent) thay vì "Đồng ý hoàn toàn" (Consensus):','van-hanh-bang-ong-thuan-consent-thay-vi-ong-y-hoan-toan-consensus',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5e44d0a-17da-48a4-98a6-bf30b747857e','0cee2bc0-9423-4da5-8432-600c34ec2482',21,'text','Việc tìm kiếm sự đồng ý 100% của tất cả mọi người trước một quyết định là nguyên nhân gây tê liệt tổ chức. Xu hướng mới chuyển sang cơ chế *Consent*: Một quyết định được thông qua nếu không có ai đưa ra được bằng chứng chứng minh nó gây nguy hại trực tiếp cho hệ thống ("Safe to try - Enough to move on").',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d2f96d1-1afd-490c-8384-5a50895e8ab3','0cee2bc0-9423-4da5-8432-600c34ec2482',22,'image',NULL,'book/07-phu-luc/44f2fa47-b58b-4578-b657-21f9203ace43-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('77008acb-fc4a-415f-9650-baa21f327896','07-phu-luc','71a627a4-a4d0-4cfd-9f44-fcbdc5de0d6a',3,'Chu kỳ hành động ngắn và liên tục (Dynamic Steering):','chu-ky-hanh-ong-ngan-va-lien-tuc-dynamic-steering',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c67b111e-1a57-4b83-9ff4-f0e7b40e949b','77008acb-fc4a-415f-9650-baa21f327896',23,'text','Thay vì ôm đồm những chiến lược quá vĩ mô, các doanh nghiệp xuất sắc dịch chuyển sang mô hình các Sprint hành động 90 ngày, kết hợp với các nhịp họp hằng tuần, hằng tháng để liên tục tối ưu hóa quy trình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2dcade0-b435-4d41-9d84-1241f6b46ea5','77008acb-fc4a-415f-9650-baa21f327896',24,'image',NULL,'book/07-phu-luc/e86c767e-d608-49c3-83ca-f31a6bcffc0b-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('710ecc9e-4cb5-4c3b-97ef-1ec539225155','07-phu-luc',NULL,2,'Biến doanh nghiệp thành sinh vật sống - Khả năng tự thích nghi của mô hình Circle','bien-doanh-nghiep-thanh-sinh-vat-song-kha-nang-tu-thich-nghi-cua-mo-hinh-circle',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bff0e86a-391a-4376-8da1-8db24054af60','710ecc9e-4cb5-4c3b-97ef-1ec539225155',25,'text','Lý do tối thượng để bạn lựa chọn mô hình **Circle (S3 Holacracy Lite)** là vì mô hình này mô phỏng hoàn hảo cách thức vận hành và tiến hóa của các sinh vật sống trong tự nhiên. Một doanh nghiệp muốn trường tồn thì không được là một cỗ máy thép, nó phải là một **Cơ thể sinh học có khả năng tự thích nghi**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f4a7504-d3a8-4266-8634-fe4f04886baf','710ecc9e-4cb5-4c3b-97ef-1ec539225155',26,'text','Hãy nhìn vào cách mô hình Circle ánh xạ một cách kỳ diệu với các nguyên lý sinh học:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('51efcca0-c04f-4b85-93bb-9a0a819c4c5b','07-phu-luc','710ecc9e-4cb5-4c3b-97ef-1ec539225155',3,'Mã Gen thống nhất (DNA) và Bản sắc cốt lõi (ROOTS)','ma-gen-thong-nhat-dna-va-ban-sac-cot-loi-roots',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ed45e9c-235e-4099-91ba-4cae7625a763','51efcca0-c04f-4b85-93bb-9a0a819c4c5b',27,'text','Mọi tế bào trong cơ thể sinh vật, dù là tế bào da, tế bào gan hay tế bào thần kinh, đều mang chung một mã DNA duy nhất. Trong hệ điều hành `Dental Empire OS`, **Core Circle** giữ vai trò như bộ mã gen này. Nó lưu trữ và bảo vệ bản sắc cốt lõi (Tầng Root), hệ giá trị văn hóa không thỏa hiệp (SKY Culture). Chính sự thống nhất về mặt DNA này giúp các Circle con dù tự chủ vận hành ở các khu vực khác nhau nhưng không bao giờ bị mất đi bản sắc thương hiệu lõi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e110cfc1-569b-4e3e-8372-c1a6f0c1edce','07-phu-luc','710ecc9e-4cb5-4c3b-97ef-1ec539225155',3,'Hệ thần kinh ngoại biên và Cơ chế xử lý điểm nghẽn (Tensions)','he-than-kinh-ngoai-bien-va-co-che-xu-ly-iem-nghen-tensions',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2af2f888-6c86-4395-b8ed-1a2dd9e82e4c','e110cfc1-569b-4e3e-8372-c1a6f0c1edce',28,'text','Khi bạn vô tình chạm tay vào một ngọn lửa, các tế bào thần kinh ở đầu ngón tay sẽ lập tức ra lệnh rút tay lại. Tín hiệu này được xử lý ngay tại tủy sống (đơn vị địa phương) chứ không chờ truyền lên não bộ phân tích rồi mới truyền ngược lệnh xuống vì nếu chờ đợi như vậy, tay bạn đã bị bỏng nặng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2d35896-60d2-4db5-aeda-5ca57c498e32','e110cfc1-569b-4e3e-8372-c1a6f0c1edce',29,'text','- Trong mô hình S3 Holacracy Lite, mỗi bất cập hay cơ hội xuất hiện trong vận hành hằng ngày được gọi là một **Tension (Xung đột/Điểm nghẽn)**.  - Nhân sự giữ vai trò chính là các "tế bào cảm giác". Khi họ gặp nghẽn, họ có toàn quyền xử lý ngay lập tức trong Miền kiểm soát (Domain) của mình hoặc đưa vào nhịp họp của Circle để giải quyết dứt điểm. Hệ thống tự sửa lỗi và phản ứng với thị trường theo thời gian thực mà không cần chờ "não bộ" (Founder) ra sắc lệnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('338abecd-2fa7-4cfc-a7d3-df2f4254b42e','07-phu-luc','710ecc9e-4cb5-4c3b-97ef-1ec539225155',3,'Sự phân bào và Tiến hóa hữu cơ','su-phan-bao-va-tien-hoa-huu-co',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70bf4acc-43f2-4bf0-a448-72120665dc6f','338abecd-2fa7-4cfc-a7d3-df2f4254b42e',30,'text','Trong tự nhiên, một sinh vật lớn lên bằng cách phân chia tế bào khi kích thước của tế bào cũ chạm ngưỡng giới hạn. Mô hình Circle áp dụng chính xác nguyên lý này để giải quyết bài toán phình to quy mô phòng khám một cách êm ái:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4a780405-a986-4e34-a240-e1a899b9ecb2','338abecd-2fa7-4cfc-a7d3-df2f4254b42e',31,'text','- Khi phòng khám còn nhỏ, một nhân sự có thể gộp nhiều vai trò (một người vừa làm lễ tân vừa làm chăm sóc khách hàng).  - Khi khối lượng công việc phình to tạo ra các Tension liên tục, Circle sẽ tự động kích hoạt cơ chế "phân bào": Tách vai trò đó ra thành một Vai trò chuyên trách mới, hoặc sinh ra một Sub-Circle (Vòng tròn con) độc lập để tự quản lý.  - Cơ thể doanh nghiệp tự tiến hóa, tự điều chỉnh cấu trúc thông qua **Governance Logbook** dựa trên nhu cầu thực tế của sự sinh trưởng, hoàn toàn không phải do sự áp đặt chủ quan mang tính lý thuyết của nhà quản lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2abe6483-9a3a-4cac-b177-dd4dfa21d1a7','338abecd-2fa7-4cfc-a7d3-df2f4254b42e',32,'text','**KẾT LUẬN:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('683c75dc-cf67-4a1a-8628-69a1ea104b24','338abecd-2fa7-4cfc-a7d3-df2f4254b42e',33,'text','Chọn mô hình quản trị Circle không phải là chọn một xu hướng thời thượng, mà là chọn một **Chiến lược tiến hóa tất yếu**. Nó biến phòng khám nha khoa của bạn từ một cỗ máy xơ cứng phụ thuộc vào năng lượng của một mình Founder, trở thành một thực thể sống tự chủ, có hệ thần kinh nhạy bén để tự thích nghi, tự vận hành và tự tăng trưởng bền vững giữa một thế giới đầy biến động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5aa84670-7442-4664-98fc-0a32553edaf7','07-phu-luc',NULL,2,'Chín bộ khái niệm lõi cấu thành nên kiến trúc và cơ chế tiến hóa của mô hình Circle:','chin-bo-khai-niem-loi-cau-thanh-nen-kien-truc-va-co-che-tien-hoa-cua-mo-hinh-cir',13,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('29c8212b-581f-4882-8a86-d75ed46a2bb6','07-phu-luc','5aa84670-7442-4664-98fc-0a32553edaf7',3,'5.1 KIẾN TRÚC ĐỊNH HÌNH (BỘ BA P-D-A)','51-kien-truc-inh-hinh-bo-ba-p-d-a',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb9fcc9f-4f59-4275-9316-bbac28dd7810','29c8212b-581f-4882-8a86-d75ed46a2bb6',34,'text','Mọi Vòng tròn (Circle) hoặc Vai trò (Role) khi được sinh ra trong hệ thống bắt buộc phải được định nghĩa bằng 3 thành tố cốt lõi này:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fdea4765-8495-4b8b-8961-fe5edd7b816b','29c8212b-581f-4882-8a86-d75ed46a2bb6',35,'text','- **Purpose (Mục tiêu tối thượng):** Lý do tồn tại của Circle/Role. Nó trả lời cho câu hỏi: *"Chúng ta làm việc này để đạt được kết quả lý tưởng nào cho tổ chức?"* Purpose đóng vai trò như kim chỉ nam cho mọi hành động.- **Domain (Miền kiểm soát độc quyền):** Tài sản, tài nguyên hoặc quyền hạn tối cao mà **chỉ riêng** Circle/Role đó được quyền sở hữu và định đoạt. Bất kỳ ai bên ngoài muốn can thiệp vào Domain này đều phải xin quyền hoặc tuân thủ chính sách (Policy) do Circle/Role đó ban hành.- **Accountability (Trách nhiệm giải trình):** Những đầu việc lớn, có tính chất liên tục và lặp đi lặp lại mà Circle/Role đó bắt buộc phải thực hiện, đo lường và báo cáo kết quả đầu ra cho toàn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3998f330-c221-45e8-8fba-07023e93df16','07-phu-luc','5aa84670-7442-4664-98fc-0a32553edaf7',3,'5.2 THỰC THỂ VẬN HÀNH (THÂN THỂ &amp; TẾ BÀO)','52-thuc-the-van-hanh-than-the-amp-te-bao',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0dd1b39b-4cc2-45b6-8d97-8c8c738e329d','3998f330-c221-45e8-8fba-07023e93df16',36,'text','- **Circle (Vòng tròn tự chủ):** Một đơn vị vận hành độc lập, tự tổ chức, tập hợp các Vai trò (Roles) có liên quan chặt chẽ với nhau về mặt chức năng để cùng giải quyết một **Purpose** cụ thể. Circle tự chịu trách nhiệm về hiệu suất, KPI và cấu trúc nội bộ của mình.- **Role (Vai trò):** Đơn vị cấu thành nhỏ nhất của hệ thống (tế bào). Role gắn liền với công việc cần làm, tách biệt hoàn toàn khỏi con người (Soul). Trong hệ thống `S.T.A.R.S People OS`, **một chức danh truyền thống có thể gộp nhiều Role**; và một nhân sự có thể sở hữu nhiều Role ở các Circle khác nhau tùy theo năng lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fcd750fb-2696-4a00-b8d0-84e1367dc061','07-phu-luc','5aa84670-7442-4664-98fc-0a32553edaf7',3,'5.3 CƠ CHẾ TIẾN HÓA &amp; RA QUYẾT ĐỊNH (HỆ THẦN KINH)','53-co-che-tien-hoa-amp-ra-quyet-inh-he-than-kinh',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62cdccec-f8d1-4105-b977-8b3efd0b2e73','fcd750fb-2696-4a00-b8d0-84e1367dc061',37,'text','- **Tension (Xung đột / Điểm nghẽn):** Khoảng cách giữa **thực tế vận hành hiện tại** và **trạng thái lý tưởng có thể đạt được**. Trong `S3 Holacracy Lite`, Tension không phải là tiêu cực, mà là **"nhiên liệu" **để cải tiến quy trình. Hệ thống tiến hóa bằng cách liên tục ghi nhận và giải quyết các Tension phát sinh hằng ngày.- **Consent (Sự đồng thuận):** Cơ chế ra quyết định tối thượng của mô hình tự chủ. Một quyết định hoặc đề xuất (Proposal) sẽ được thông qua khi **không có ai đưa ra phản đối (Objection) dựa trên bằng chứng chứng minh quyết định đó gây hại cho tổ chức**. Triết lý cốt lõi là: *"Đủ an toàn để thử, đủ tốt để tiến lên" (Safe to try, Enough to move on)*.- **Escalation (Leo thang hệ thống):** Quy trình chuyển giao vấn đề hoặc xung đột lên Circle cấp cao hơn (Core Circle) để xử lý. Escalation xuất hiện khi hai Circle con chồng lấn ranh giới mà không tự thỏa hiệp được, hoặc một đề xuất vượt quá giới hạn ngân sách/Domain hiện tại của Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ea671731-74e2-4738-b25a-67256e7cc0ce','07-phu-luc','5aa84670-7442-4664-98fc-0a32553edaf7',3,'5.4 CƠ SỞ HẠ TẦNG QUẢN TRỊ (BỘ NHỚ HỆ THỐNG)','54-co-so-ha-tang-quan-tri-bo-nho-he-thong',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4b51f39-d8aa-4de3-aa99-207b7c9b6615','ea671731-74e2-4738-b25a-67256e7cc0ce',38,'text','- **Governance Logbook (Sổ tay quản trị):** "Kinh thánh" lưu trữ cấu trúc vận hành của tổ chức. Đây là file dữ liệu mở (Notion/Lark) ghi nhận thời gian thực: *Hệ thống đang có những Circle nào? Ai nắm giữ những Role nào? Domain và Accountability chi tiết là gì? Các Chính sách (Policy) nào đang có hiệu lực?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec970395-6656-422b-bfb6-8dbd42808ec1','ea671731-74e2-4738-b25a-67256e7cc0ce',39,'text','**Tóm tắt quy luật vận hành:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3794741f-805d-4f63-91f3-f9e4e6cb267a','ea671731-74e2-4738-b25a-67256e7cc0ce',40,'text','Nhân sự nắm giữ **Role** trong một **Circle** được toàn quyền quyết định thực thi trong **Domain** của mình nhằm phục vụ **Purpose** hệ thống, liên tục chuyển hóa các **Tension** thành cải tiến thông qua cơ chế **Consent**, và mọi thay đổi về mặt cấu trúc bắt buộc phải được ghi nhận công khai vào **Governance Logbook**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2ecfad89-cf4b-4278-84be-2625db7b5068','07-phu-luc',NULL,1,'7.2 TRIẾT LÝ CỦA QUẢN TRỊ EMPIRE CIRCLE','72-triet-ly-cua-quan-tri-empire-circle',18,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d4af7ee2-d51a-45c9-9db0-e3bd78e78be6','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'ĐỊNH NGHĨA CIRCLE (VÒNG TRÒN CHUYÊN MÔN)','inh-nghia-circle-vong-tron-chuyen-mon',19,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8e8e160f-79ec-460f-819e-23c8c248ac1d','07-phu-luc','d4af7ee2-d51a-45c9-9db0-e3bd78e78be6',3,'Circle là gì?','circle-la-gi',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46d133f6-dca0-4cbd-8d3c-967b45fc810f','8e8e160f-79ec-460f-819e-23c8c248ac1d',41,'text','Trong hệ điều hành **Dental Empire OS**, **Circle (Vòng tròn chuyên môn)** là một đơn vị vận hành độc lập, tự chủ và tự tổ chức, được gắn liền với một **Mục tiêu tối thượng (Purpose)** cụ thể nhằm thực thi một phần chiến lược tổng thể của tổ chức. Circle tập hợp các vai trò (Roles) có liên quan chặt chẽ với nhau về mặt chức năng để cùng giải quyết công việc mà không bị chia cắt bởi ranh giới cấp bậc hành chính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('805d4e6b-1c03-451e-b1e4-b1dde0eebe47','07-phu-luc','d4af7ee2-d51a-45c9-9db0-e3bd78e78be6',3,'Circle khác gì với Team, Department hoặc Phòng ban truyền thống?','circle-khac-gi-voi-team-department-hoac-phong-ban-truyen-thong',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ac7d34b-6ff6-47bd-b8ba-204ac8140387','805d4e6b-1c03-451e-b1e4-b1dde0eebe47',42,'image',NULL,'book/07-phu-luc/929e1d0d-0e1f-47fb-a52c-73aa22cbc844-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5b57a429-58ca-413a-905b-269170e7cece','07-phu-luc','d4af7ee2-d51a-45c9-9db0-e3bd78e78be6',3,'Circle trong S3 Holacracy Lite dùng để làm gì?','circle-trong-s3-holacracy-lite-dung-e-lam-gi',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('886a1c45-d39f-42d7-a529-6507a6ae3ffb','5b57a429-58ca-413a-905b-269170e7cece',43,'text','Trong phiên bản cải tiến **S3 Holacracy Lite** (thiết kế riêng cho ngành Nha khoa), Circle được sử dụng để:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('804eef1b-f5ab-4ca2-b2fc-5795dcfd63a4','5b57a429-58ca-413a-905b-269170e7cece',44,'text','- **Phân rã quyền lực tối cao của Founder:** Chuyển giao quyền từ "con người" sang "hệ thống quy trình và vai trò".- **Tăng tốc độ thực thi:** Loại bỏ việc duyệt qua nhiều cấp. Ai giữ Vai trò nào thì có toàn quyền quyết định trong Miền kiểm soát (Domain) của vai trò đó.- **Tạo ra cơ chế tự sửa lỗi:** Giúp tổ chức linh hoạt thích ứng với sự thay đổi của thị trường thông qua việc liên tục tối ưu hóa năng lực nội tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34d9f553-d1e7-410c-9027-8dcd124f4f8b','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'VÌ SAO PHÒNG KHÁM CẦN CIRCLE?','vi-sao-phong-kham-can-circle',23,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cdba89d9-71e9-456e-92ce-984322f355a9','07-phu-luc','34d9f553-d1e7-410c-9027-8dcd124f4f8b',3,'Vấn đề của mô hình quản trị bằng cá nhân (Founder-led)','van-e-cua-mo-hinh-quan-tri-bang-ca-nhan-founder-led',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebec2d35-b6d9-476c-8db8-e5ffa010c95c','cdba89d9-71e9-456e-92ce-984322f355a9',45,'text','Khi phòng khám vận hành hoàn toàn dựa trên năng lực cá nhân của Founder hoặc một vài quản lý cốt cán, hệ thống sẽ đối mặt với "bẫy sinh trưởng":',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47ea6edf-5691-4e3f-a3d1-d6b2972a8ce5','cdba89d9-71e9-456e-92ce-984322f355a9',46,'text','- **Nghẽn cổ chai quyết định (CEO Bottleneck):** Mọi việc từ mua vật liệu tiêu hao, giảm giá cho khách hàng, đến duyệt bài đăng Facebook đều phải chờ Founder ký duyệt. Founder kiệt sức, còn nhân sự thụ động.- **Sự phụ thuộc rủi ro:** Nếu Bác sĩ trưởng hoặc Founder vắng mặt, phòng khám lập tức rơi vào trạng thái tê liệt hoặc sụt giảm doanh thu.- **Sự thiếu minh bạch cảm tính:** Lương thưởng, đánh giá năng lực và quy trình làm việc thường thay đổi theo tâm trạng của nhà quản lý thay vì dựa trên dữ liệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('192c295a-30b7-46d8-b5e8-90a46cdf26c4','07-phu-luc','34d9f553-d1e7-410c-9027-8dcd124f4f8b',3,'Khi nào phòng khám bắt đầu cần cấu trúc Circle?','khi-nao-phong-kham-bat-au-can-cau-truc-circle',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c706cd9a-b341-4f50-8460-07a53545c931','192c295a-30b7-46d8-b5e8-90a46cdf26c4',47,'text','Phòng khám cần kích hoạt cấu trúc Circle khi chạm tới các cột mốc hoặc dấu hiệu sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67a64e7f-faa6-4303-84b6-4b1bbe561fd2','192c295a-30b7-46d8-b5e8-90a46cdf26c4',48,'text','- **Về quy mô:** Nhân sự đạt từ 12 - 15 người trở lên, hoặc bắt đầu vận hành từ 2 chi nhánh/cơ sở độc lập.- **Về vận hành:** Founder không còn thời gian làm chuyên môn lâm sàng vì bận giải quyết các vụn vặt sự vụ.- **Về chỉ số:** Data khách hàng đổ về nhiều nhưng tỷ lệ chốt thấp, các bộ phận đổ lỗi chéo cho nhau (Marketing bảo Sales tư vấn kém, Sales bảo Marketing mang về Lead rác, Bác sĩ bảo Sales cam kết quá đà).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('091b09a3-ed3f-43d0-8603-f427b3ac375e','07-phu-luc','34d9f553-d1e7-410c-9027-8dcd124f4f8b',3,'Circle giải quyết chồng chéo, nghẽn quyết định và phụ thuộc Founder ra sao?','circle-giai-quyet-chong-cheo-nghen-quyet-inh-va-phu-thuoc-founder-ra-sao',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6529525c-ba63-4e74-8cfd-bfb8b75d0a13','091b09a3-ed3f-43d0-8603-f427b3ac375e',49,'text','- **Xóa bỏ chồng chéo:** Mỗi Circle có một **Domain (Miền kiểm soát)** độc quyền. Không ai có quyền can thiệp vào Domain của người khác nếu không có sự đồng thuận (Consent).- **Thông nghẽn quyết định:** Thay vì hỏi "Tôi có được làm không?", nhân sự giữ vai trò chỉ cần check: *"Việc này có nằm trong Domain của tôi không? Có phục vụ Purpose của Circle không? Có vi phạm Policy không?"*. Nếu thỏa mãn, họ tự làm và tự chịu trách nhiệm.- **Giải phóng Founder:** Founder chỉ quản lý Vòng tròn Tổng thể (Anchor Circle) ở tầng Chiến lược và Bản sắc (Root), không can thiệp vào cách thực thi của các Sub-Circle (Vòng tròn con).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9564b840-1648-43f5-b7c2-46bab3053504','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'CẤU TRÚC BÊN TRONG CỦA MỘT CIRCLE','cau-truc-ben-trong-cua-mot-circle',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79b17799-75c4-41f7-8b08-51944df39926','9564b840-1648-43f5-b7c2-46bab3053504',50,'text','Để một Circle vận hành chuẩn hóa, cấu trúc của nó bắt buộc phải được định nghĩa bằng 3 yếu tố cốt lõi (PDA) và các Vai trò cấu thành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e928ce22-864f-498f-8a7b-0081d99d5e01','9564b840-1648-43f5-b7c2-46bab3053504',51,'image',NULL,'book/07-phu-luc/2723266b-19bf-4797-81b6-3bc854f5ce38-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('733e7ee9-2ca3-400d-adb4-70f946410cc9','07-phu-luc','9564b840-1648-43f5-b7c2-46bab3053504',3,'Purpose (Mục tiêu tối thượng)','purpose-muc-tieu-toi-thuong',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dad4cb49-a6b9-47ad-89d9-8d0e419d7f07','733e7ee9-2ca3-400d-adb4-70f946410cc9',52,'text','Là lý do tồn tại của Circle. Định hướng cho mọi hành động và quyết định bên trong vòng tròn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('534948a6-2ae0-4f01-b4d7-623cfb5407f7','733e7ee9-2ca3-400d-adb4-70f946410cc9',53,'text','- *Ví dụ (Growth Circle):* "Kiến tạo dòng chảy khách hàng tiềm năng chất lượng cao ổn định và tối ưu hóa tỷ lệ chuyển đổi doanh thu cho phòng khám."',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5fc6979e-c007-46cd-bcbd-4649b7e4fa20','07-phu-luc','9564b840-1648-43f5-b7c2-46bab3053504',3,'Domain (Miền kiểm soát độc quyền)','domain-mien-kiem-soat-oc-quyen',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('583bc586-ed54-49f6-adc6-64e5a7644f1f','5fc6979e-c007-46cd-bcbd-4649b7e4fa20',54,'text','Là tài sản, tài nguyên hoặc quyền hạn mà CHỈ RIÊNG Circle này có quyền sở hữu và định đoạt. Bất kỳ ai bên ngoài muốn đụng vào Domain này đều phải xin quyền hoặc tuân thủ chính sách của Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b8e5895-3cfd-4f43-8a02-7a78f28b567e','5fc6979e-c007-46cd-bcbd-4649b7e4fa20',55,'text','- *Ví dụ:* Quyền quản trị các kênh Social Media, Ngân sách Marketing được duyệt, Hệ thống CRM, Kịch bản chốt sales.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('18160718-e71b-4395-863c-5e7c8e478566','07-phu-luc','9564b840-1648-43f5-b7c2-46bab3053504',3,'Accountability (Trách nhiệm giải trình)','accountability-trach-nhiem-giai-trinh',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fc9e4e2-9e5c-4768-b9b5-dc73abb31aaa','18160718-e71b-4395-863c-5e7c8e478566',56,'text','Là những hoạt động cốt lõi, liên tục mà Circle có trách nhiệm phải thực hiện và báo cáo kết quả đầu ra cho toàn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9375baef-fb51-4298-a284-fd68740fa90a','18160718-e71b-4395-863c-5e7c8e478566',57,'text','- *Ví dụ:* Đo lường CPL (Chi phí trên Lead), liên tục cập nhật SOP tư vấn, duy trì nhịp độ chiến dịch truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e51aeec0-d737-4112-bd26-418ffe2948ab','07-phu-luc','9564b840-1648-43f5-b7c2-46bab3053504',3,'Các Role (Vai trò) cốt lõi bên trong Circle','cac-role-vai-tro-cot-loi-ben-trong-circle',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9403b204-ba5a-4660-bee7-05230ee5cf02','e51aeec0-d737-4112-bd26-418ffe2948ab',58,'text','Mỗi Circle trong cấu trúc S3 Holacracy Lite luôn có 4 vai trò cấu trúc cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1078cbf-dde6-4a1b-b98d-e0377d54ed91','e51aeec0-d737-4112-bd26-418ffe2948ab',59,'text','- **Circle Lead (Đầu mối điều phối xuống):** Do Circle mẹ chỉ định. Có trách nhiệm định hướng chiến lược, phân bổ ngân sách, gán người vào các vai trò vận hành bên trong Circle và quản lý hiệu suất tổng thể.- **Rep Link (Đầu mối đại diện lên):** Do các thành viên trong Circle bầu chọn ra. Đại diện cho tiếng nói của Circle để mang các Xung đột (Tensions) hoặc đề xuất lên Circle mẹ, đảm bảo cấu trúc không bị độc tài bởi Circle Lead.- **Facilitator (Người điều phối cuộc họp):** Điều phối các buổi họp Tactical và Governance tuân thủ đúng quy trình, giữ cho cuộc họp tập trung, không bị lan man và giải quyết dứt điểm các thẻ Tension.- **Secretary (Thư ký Circle):** Ghi chép tài liệu, cập nhật **Governance Logbook**, theo dõi tiến độ công việc và lưu trữ lịch sử các quyết định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e54ff276-4cbe-4878-8163-66547412e666','e51aeec0-d737-4112-bd26-418ffe2948ab',60,'text','*Lưu ý: Bên cạnh 4 vai trò cấu trúc này là các ****Operational Roles (Vai trò vận hành)**** thực tế như: Vai trò Content Creator, Vai trò Ads Optimizer, Vai trò Tele-sales, v.v.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc7759ca-bb37-4e71-8311-0fb357b59024','e51aeec0-d737-4112-bd26-418ffe2948ab',61,'image',NULL,'book/07-phu-luc/bb0a4a5a-311f-47ef-aebc-3c4eb01371e5-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('778ff962-4470-4e59-9e67-613511d31273','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'QUYỀN HẠN CỦA CIRCLE: NGUYÊN TẮC VẬN HÀNH AN TOÀN','quyen-han-cua-circle-nguyen-tac-van-hanh-an-toan',32,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('01fc01f1-f9a4-4ab5-9711-3c10419cea04','07-phu-luc','778ff962-4470-4e59-9e67-613511d31273',3,'Circle được quyết định những gì?','circle-uoc-quyet-inh-nhung-gi',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ea224cb-e82f-4230-ab08-18db7b65fd32','01fc01f1-f9a4-4ab5-9711-3c10419cea04',62,'text','Circle được tự chủ hoàn toàn trong việc đưa ra quyết định thực thi (Quyết định Tactical) hoặc thay đổi cấu trúc nội bộ (Quyết định Governance) miễn là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94814fdf-3db0-469c-9e82-b1ad786464de','01fc01f1-f9a4-4ab5-9711-3c10419cea04',63,'text','- Hành động đó nhằm phục vụ **Purpose** của Circle.- Hành động nằm hoàn toàn trong **Domain** của Circle.- Hành động không vi phạm bất kỳ **Policy (Chính sách)** chung nào của Vòng tròn tổng thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f5719e2c-1660-428a-b2a3-6dd4c1340fa0','07-phu-luc','778ff962-4470-4e59-9e67-613511d31273',3,'Khi nào Circle cần Consent (Sự đồng thuận)?','khi-nao-circle-can-consent-su-ong-thuan',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a8d0f49-011e-4ec8-b072-7ba2cf2f493b','f5719e2c-1660-428a-b2a3-6dd4c1340fa0',64,'text','Circle cần tiến hành quy trình lấy **Consent** (Không có ai phản đối vì gây hại cho hệ thống) trong các trường hợp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f567a434-2d83-46da-9ee0-292a57d8a151','f5719e2c-1660-428a-b2a3-6dd4c1340fa0',65,'text','- Khi muốn ban hành hoặc chỉnh sửa một **Policy** nội bộ của Circle.- Khi tạo mới, xóa bỏ hoặc thay đổi Trách nhiệm giải trình (Accountability) của một Vai trò bên trong Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7531a01f-cd07-4c54-9b35-b98a4e0e65aa','07-phu-luc','778ff962-4470-4e59-9e67-613511d31273',3,'Khi nào Circle cần Escalation (Leo thang/Trình cấp cao)?','khi-nao-circle-can-escalation-leo-thangtrinh-cap-cao',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f17d8102-defa-4109-a546-52212de3cdc1','7531a01f-cd07-4c54-9b35-b98a4e0e65aa',66,'text','Cần đưa vấn đề lên Circle cấp trên (Anchor Circle hoặc Ban chiến lược) khi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('647285ea-8371-4321-a374-59516d959050','7531a01f-cd07-4c54-9b35-b98a4e0e65aa',67,'text','- Xung đột xảy ra giữa 2 Circle khác nhau mà Rep Link của hai bên không thể tự thỏa hiệp.- Circle muốn thay đổi hoặc mở rộng **Domain** của chính mình (vì điều này trực tiếp ảnh hưởng đến tài nguyên tổng của tổ chức).- Cần xin vượt hạn mức ngân sách chiến lược đã được phê duyệt ban đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0a9ad7ff-4e74-425b-8917-66ddbe24d360','07-phu-luc','778ff962-4470-4e59-9e67-613511d31273',3,'Nguyên tắc: "Không lạm quyền nhưng cũng không bị bó tay"','nguyen-tac-khong-lam-quyen-nhung-cung-khong-bi-bo-tay',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46d5c4da-6f45-4205-bacb-e81803c01f06','0a9ad7ff-4e74-425b-8917-66ddbe24d360',68,'text','Vận hành theo nguyên tắc tư duy tối thượng của Holacracy: **"Safe to try - Enough to move on"** (Đủ an toàn để thử - Đủ tốt để tiến lên). Nhân sự không cần tìm kiếm một quyết định "hoàn hảo". Nếu một đề xuất không gây nguy hại trực tiếp hoặc không làm tổn thương phòng khám ngay lập tức, Circle có quyền thực thi ngay để thử nghiệm dữ liệu thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('00ee7523-b42b-46f8-837e-5600bc7a77ec','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'GOVERNANCE (QUẢN TRỊ TRẤN CẤU TRÚC) CỦA CIRCLE','governance-quan-tri-tran-cau-truc-cua-circle',37,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f70bd13c-a01c-45a1-878d-791aed6c2ecd','07-phu-luc','00ee7523-b42b-46f8-837e-5600bc7a77ec',3,'Governance Logbook (Sổ tay quản trị)','governance-logbook-so-tay-quan-tri',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b2d3ff8-38ad-4e7e-8290-fc1e7b6cc77e','f70bd13c-a01c-45a1-878d-791aed6c2ecd',69,'text','Là "Kinh thánh vận hành" của Circle. Tài liệu này được Thư ký cập nhật liên tục trên các nền tảng số (Notion/Lark/ClickUp) và ở trạng thái mở cho toàn phòng khám cùng xem. Logbook ghi rõ: *Circle này gồm những vai trò nào? Ai đang giữ vai trò đó? Domain là gì? Các Policy hiện hành là gì?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('22954fa5-532c-4bbe-8a85-d659eb37fa8c','07-phu-luc','00ee7523-b42b-46f8-837e-5600bc7a77ec',3,'Policy (Chính sách)','policy-chinh-sach',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('27d98ece-cd1f-42d4-8300-06bd61483050','22954fa5-532c-4bbe-8a85-d659eb37fa8c',70,'text','Là các bộ quy tắc biên giới quy định hành vi inside/outside Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('083b6182-dcaa-49b2-b113-f9541c5b9753','22954fa5-532c-4bbe-8a85-d659eb37fa8c',71,'text','- *Ví dụ một Policy của Circle Trải nghiệm (Patient Circle):* "Mọi phản hồi tiêu cực của khách hàng trên Fanpage phải được phản hồi bằng văn bản theo đúng khung xử lý khủng hoảng trong vòng tối đa 7 phút kể từ khi ghi nhận."',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d6826035-d451-4e4e-8374-a59df55ec57e','07-phu-luc','00ee7523-b42b-46f8-837e-5600bc7a77ec',3,'Quy trình thay đổi (Role, KPI, Decision Log)','quy-trinh-thay-oi-role-kpi-decision-log',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7320e4ef-57e8-4017-8be0-5b4c2e78b600','d6826035-d451-4e4e-8374-a59df55ec57e',72,'text','- **Role Change:** Không dựa trên cảm xúc yêu ghét. Khi một nhân sự giữ vai trò liên tục không đạt KPI đặt ra cho Vai trò đó, Circle Lead có quyền gán (Assign) nhân sự khác vào vai trò này.- **KPI Change:** Chỉ số đo lường hiệu suất của vai trò được tinh chỉnh trong các cuộc họp Governance hằng tháng để bám sát thực tế thị trường.- **Decision Log (Nhật ký quyết định):** Lưu trữ lại mọi quyết định mang tính lịch sử để làm tài liệu đối chiếu cho nhân sự mới, tránh việc lặp lại các lỗi hệ thống cũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a606c67c-ef18-4f28-a581-ef15c68ee302','07-phu-luc','00ee7523-b42b-46f8-837e-5600bc7a77ec',3,'Khi nào cần thay đổi cấu trúc Circle?','khi-nao-can-thay-oi-cau-truc-circle',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db583007-9247-4841-bd73-6d527e6ae7a7','a606c67c-ef18-4f28-a581-ef15c68ee302',73,'text','Một Circle chỉ thay đổi cấu trúc (tách vai trò, gộp vai trò, sinh ra Sub-Circle mới) khi và chỉ khi có một **Tension (Xung đột/Điểm nghẽn)** thực tế xuất hiện từ vận hành hằng ngày, chứng minh rằng cấu trúc hiện tại không còn đáp ứng được Purpose nữa. *Tuyệt đối không thay đổi cấu trúc dựa trên các lý thuyết suông.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3832124d-e223-4d61-bbb3-89b0e9e835c0','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'NHỊP ĐỘ HỌP (MEETING RHYTHM) CỦA CIRCLE','nhip-o-hop-meeting-rhythm-cua-circle',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9adffd70-9c79-45e9-975f-fc2fad0932af','3832124d-e223-4d61-bbb3-89b0e9e835c0',74,'text','Để vận hành hệ thống tự chủ mà không bị rơi vào tình trạng hỗn loạn, các Circle bắt buộc phải duy trì 4 nhịp họp cố định với các mục tiêu hoàn toàn tách biệt:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d833048-a170-4938-b2e5-15e9e654b9b6','3832124d-e223-4d61-bbb3-89b0e9e835c0',75,'image',NULL,'book/07-phu-luc/5050d1b6-d70e-4d45-995a-d091a479d404-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4b58070e-8b89-496c-853e-9d18ad06c0ea','07-phu-luc','3832124d-e223-4d61-bbb3-89b0e9e835c0',3,'Daily Huddle (15 phút - Định kỳ hằng ngày)','daily-huddle-15-phut-inh-ky-hang-ngay',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f885504-8094-4dc5-ab63-5ba665f7ebf7','4b58070e-8b89-496c-853e-9d18ad06c0ea',76,'text','- **Mục tiêu:** Đồng bộ nhanh công việc trong ngày, phát hiện nghẽn phát sinh ngay lập tức.- **Cách chạy:** Đứng họp hoặc họp nhanh đầu giờ. Từng vai trò trả lời 3 câu hỏi: *Hôm qua tôi đã làm gì phục vụ vai trò? Hôm nay tôi sẽ làm gì? Tôi đang gặp khó khăn (nghẽn) ở đâu cần hỗ trợ?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('14d51cac-fedf-4a40-b1cb-59644eaedbc6','07-phu-luc','3832124d-e223-4d61-bbb3-89b0e9e835c0',3,'Weekly Tactical Meeting (60 - 90 phút - Định kỳ hằng tuần)','weekly-tactical-meeting-60-90-phut-inh-ky-hang-tuan',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f680ca1-76f0-4045-b430-e3c7e8bb74bf','14d51cac-fedf-4a40-b1cb-59644eaedbc6',77,'text','- **Mục tiêu:** Đồng bộ tiến độ công việc và tháo gỡ các thẻ công việc (Tactical Tensions).- **Chương trình nghị sự chuẩn (Agenda):**Check-in cảm xúc.- Review Checklist & Chỉ số cốt lõi (Metric review) của từng vai trò.- Cập nhật tiến độ các dự án lớn (Project updates).- Xây dựng danh sách các vấn đề cần giải quyết (Triage Tensions).- Xử lý dứt điểm từng Tension để đưa ra hành động cụ thể (Next-actions).- Check-out.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2a8ba79e-6373-46dc-81ba-54f918e810ba','07-phu-luc','3832124d-e223-4d61-bbb3-89b0e9e835c0',3,'Monthly Governance Meeting (60 - 90 phút - Định kỳ hằng tháng)','monthly-governance-meeting-60-90-phut-inh-ky-hang-thang',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('811d69bd-2d58-4e15-9c8a-fabb165c7781','2a8ba79e-6373-46dc-81ba-54f918e810ba',78,'text','- **Mục tiêu:** Sửa đổi cấu trúc vận hành của Circle dựa trên điểm nghẽn tích lũy. *Không bàn chuyện thực thi công việc tại cuộc họp này.*- **Đầu ra:** Ban hành Policy mới, bổ sung Trách nhiệm giải trình cho một vai trò, hoặc bầu chọn các vai trò cấu trúc mới (Facilitator, Secretary).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('14e40813-26ba-408c-a5b4-c142fa117252','07-phu-luc','3832124d-e223-4d61-bbb3-89b0e9e835c0',3,'Monthly S.T.A.R.S Review (120 phút - Định kỳ hằng tháng)','monthly-stars-review-120-phut-inh-ky-hang-thang',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f8e7cdd-c3b6-4c4b-9e9e-de7bf465e414','14e40813-26ba-408c-a5b4-c142fa117252',79,'text','- **Mục tiêu:** Cuộc họp kiểm toán toàn diện sức khỏe của Circle dựa trên 5 cánh S.T.A.R.S.- **Cách chạy:** Đánh giá độ lệch giữa Strategy đặt ra và Doanh thu/Trải nghiệm thực tế đạt được, tìm nguyên nhân gốc rễ và lập kế hoạch OKR/Sprint hành động cho 90 ngày tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f1f4954c-612a-49a3-99ac-0f1dbc2c1f4f','07-phu-luc','3832124d-e223-4d61-bbb3-89b0e9e835c0',3,'Cách chuyển hóa một Tension (Xung đột) thành Cải tiến thực tế','cach-chuyen-hoa-mot-tension-xung-ot-thanh-cai-tien-thuc-te',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6f5710c-9849-4477-a613-8b9a82298e03','f1f4954c-612a-49a3-99ac-0f1dbc2c1f4f',80,'text','Khi một nhân sự gặp bất cập (Tension), quy trình xử lý theo S3 Holacracy Lite diễn ra như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c5e2d5af-c41d-4d82-9146-511858fa3baf','f1f4954c-612a-49a3-99ac-0f1dbc2c1f4f',81,'text','\\text{Ghi nhận Tension} \\rightarrow \\text{Đưa vào Agenda cuộc họp} \\rightarrow \\text{Đưa ra Proposal (Đề xuất)} \\rightarrow \\text{Quy trình lấy Consent} \\rightarrow \\text{Cập nhật vào Logbook/SOP}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('405ea8b2-9251-4ea0-a81c-70c084b01a66','07-phu-luc','2ecfad89-cf4b-4278-84be-2625db7b5068',2,'LỘ TRÌNH TRIỂN KHAI CẤU TRÚC CIRCLE CHO PHÒNG KHÁM','lo-trinh-trien-khai-cau-truc-circle-cho-phong-kham',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d21335e6-b39a-4782-af4b-d17c70b24e3b','405ea8b2-9251-4ea0-a81c-70c084b01a66',82,'text','Để tránh tình trạng tổ chức bị "sốc phản vệ" khi chuyển đổi từ mô hình truyền thống sang mô hình tự chủ Circle, cấu trúc R.O.A.D.M.A.P yêu cầu tuân thủ nghiêm ngặt 4 bước lộ trình sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1fafb10c-318a-4e63-ad25-d57976e4ab80','07-phu-luc','405ea8b2-9251-4ea0-a81c-70c084b01a66',3,'Bước 1: Áp dụng từ phạm vi một phòng khám nhỏ (Proto-Circle)','buoc-1-ap-dung-tu-pham-vi-mot-phong-kham-nho-proto-circle',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('860d90d7-54c8-4234-9efa-fcb8b4b2e5e5','1fafb10c-318a-4e63-ad25-d57976e4ab80',83,'text','Đừng vội vã chia tách hệ thống thành 5 Circle hoành tráng ngay ngày đầu tiên. Hãy bắt đầu bằng cách gom toàn bộ phòng khám hiện tại thành một **Vòng tròn Nguyên mẫu (Proto-Circle)**. Founder đóng vai trò Circle Lead, huấn luyện cho đội ngũ làm quen với tư duy thảo luận dựa trên khái niệm "Vai trò" (Role) và "Điểm nghẽn" (Tension) trong các cuộc họp Weekly Tactical hằng tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f539be37-a619-45d6-a3cb-ef18b3e065fd','07-phu-luc','405ea8b2-9251-4ea0-a81c-70c084b01a66',3,'Bước 2: Nguyên tắc "Gộp role trước, tách Circle sau"','buoc-2-nguyen-tac-gop-role-truoc-tach-circle-sau',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('978b40b6-fa50-490a-bed6-15387448b0cc','f539be37-a619-45d6-a3cb-ef18b3e065fd',84,'text','Trong giai đoạn đầu phòng khám còn ít nhân sự, **một người sẽ nắm giữ nhiều vai trò**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5b8c9a1-b179-41cc-b876-e99bd1d84dc2','f539be37-a619-45d6-a3cb-ef18b3e065fd',85,'text','- *Ví dụ:* Một bạn Lễ tân có thể vừa nắm giữ Vai trò *Receptionist* (thuộc Growth Circle) vừa nắm giữ Vai trò *Customer Care Speed* (thuộc Patient Circle).- Khi khối lượng công việc của một Vai trò phình to ra và doanh thu phòng khám tăng trưởng đủ để tuyển dụng nhân sự chuyên trách, lúc đó mới chính thức bóc tách Vai trò đó ra giao cho người mới và thành lập các Sub-Circle riêng biệt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5090e162-35f7-46a4-a8fd-497d1762dd42','07-phu-luc','405ea8b2-9251-4ea0-a81c-70c084b01a66',3,'Bước 3: Đưa Dashboard và Governance Logbook vào vận hành ngay lập tức','buoc-3-ua-dashboard-va-governance-logbook-vao-van-hanh-ngay-lap-tuc',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7870f53e-a5ee-422d-a043-b816043eb6aa','5090e162-35f7-46a4-a8fd-497d1762dd42',86,'text','Hệ thống tự chủ chỉ có thể vận hành khi thông tin đối xứng và minh bạch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4c79d45-8033-431b-bf9f-9653118c561a','5090e162-35f7-46a4-a8fd-497d1762dd42',87,'text','- Kích hoạt ngay một file/dashboard theo dõi chỉ số hằng ngày của phòng khám (Số lead, số hẹn, doanh thu, tỷ lệ chốt).- Xây dựng file **Governance Logbook** đầu tiên (có thể dùng Notion hoặc Lark Base) để định nghĩa rõ ràng: *Ai đang chịu trách nhiệm cho chỉ số nào? Quyền hạn của họ đến đâu?* Toàn bộ nhân sự phải được ký cam kết đã đọc và hiểu rõ quyền hạn/trách nhiệm của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5f64aa05-acda-454d-aaa8-82db50a85346','07-phu-luc','405ea8b2-9251-4ea0-a81c-70c084b01a66',3,'Bước 4: Mở rộng dần theo độ trưởng thành (Tầng Mature &amp; Align) của hệ thống','buoc-4-mo-rong-dan-theo-o-truong-thanh-tang-mature-amp-align-cua-he-thong',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c427e03-fca1-4bc6-8048-cda9070f2ce9','5f64aa05-acda-454d-aaa8-82db50a85346',88,'text','Khi các nhân sự cốt cán bên trong các Circle đã thuần thục kỹ năng tự xử lý Tension, biết tự chạy vòng lặp S.T.A.R.S hằng tháng để tối ưu hiệu suất, Founder bắt đầu rút dần khỏi vai trò điều hành chi tiết. Lúc này, phòng khám chính thức bước sang tầng **Mature (Trưởng thành và ổn định bằng hệ thống)** và sẵn sàng cho việc đóng gói, nhân bản cấu trúc Circle này sang các chi nhánh mới trong hành trình xây dựng "Đế chế Nha khoa" bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('895f9913-7b52-44cb-9fcb-2e65bd5327bc','5f64aa05-acda-454d-aaa8-82db50a85346',89,'image',NULL,'book/07-phu-luc/02017411-f555-49be-94b7-1c8889199194-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4c02eb56-fce1-4468-b5ac-47040096417d','07-phu-luc',NULL,1,'7.3 PLAYBOOK VẬN HÀNH - CẤU TRÚC 5+1 CIRCLE','73-playbook-van-hanh-cau-truc-51-circle',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('788b4510-e556-4c7f-83bc-635ece650c47','4c02eb56-fce1-4468-b5ac-47040096417d',90,'image',NULL,'book/07-phu-luc/c9535a3d-086a-4914-b6d2-ab4f7738072d-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('21c9fcdd-505d-48cf-bbdb-e9e89d7496c0','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'Core Circle (Vòng tròn Trung tâm / Ban Chiến lược)Purpose (Mục tiêu): Định hình bản sắc cốt lõi, phê duyệt kiến trúc hệ thống và phân bổ tài nguyên chiến lược để đảm bảo sự phát triển ổn định, bền vững của tổ chức.  Domain (Miền kiểm soát): Bản sắc thương hiệu lõi, văn hóa tổ chức (SKY Culture), kiến trúc phân quyền hệ thống (S3 và quỹ ngân sách chiến lược toàn hệ thống.  Accountabilities (Trách nhiệm giải trình): Thẩm định chiến lược OKRs hằng quý; phê duyệt ngân sách và định mức chi phí cho các Circle con; giải quyết các xung đột liên Circle vượt cấp (Escalation); bảo vệ tính toàn vẹn của hệ điều hành Dental Empire OS.  Roles (Vai trò cốt lõi): Circle Lead (Founder/CEO), Rep Link (đại diện được bầu từ các Circle con), Facilitator, Secretary.  KPI (Chỉ số đo lường): Tốc độ tăng trưởng doanh thu tổng, Biên lợi nhuận ròng (Net Profit Margin), Chỉ số sức khỏe tổ chức (OHI).Meeting Rhythm (Nhịp họp): Quarterly Strategy Review (Họp chiến lược quý), Monthly Coordination Meeting (Họp điều phối tháng).  Governance / Decision Rules (Quy tắc quyết định): Quyết định thay đổi kiến trúc hệ thống hoặc điều chỉnh Domain của các Circle con bắt buộc phải đạt sự đồng thuận (Consent) của tất cả thành viên trong Core Circle.','core-circle-vong-tron-trung-tam-ban-chien-luocpurpose-muc-tieu-inh-hinh-ban-sac-',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80f82c05-8a25-4ce0-9b87-5949616e4776','21c9fcdd-505d-48cf-bbdb-e9e89d7496c0',91,'image',NULL,'book/07-phu-luc/c9817b9f-539c-4b94-8eee-9232419929b8-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('74e21e61-449b-4dba-bf35-f21f82b66f4a','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'Growth Circle (Vòng tròn Tăng trưởng - Thu hút Đầu phễu) Purpose (Mục tiêu): Xây dựng tài sản uy tín và tối ưu hóa các kênh truyền thông số nhằm tạo ra dòng dữ liệu khách hàng tiềm năng (Lead) chất lượng cao, ổn định cho phòng khám.  Domain (Miền kiểm soát): Các kênh truyền thông số (Social Media Pages, Website), Tài sản uy tín (Trust Assets), Ngân sách quảng cáo được duyệt, Hệ thống dữ liệu Marketing đầu phễu.  Accountabilities (Trách nhiệm giải trình): Lập kế hoạch và tối ưu hóa các chiến dịch quảng cáo (Ads); sản xuất nội dung số (Content Marketing); xây dựng mạng lưới truyền thông (Media Network); đo lường và báo cáo chính xác hiệu quả chuyển đổi từ người tiếp cận thành Lead.  Roles (Vai trò cốt lõi): Circle Lead (Marketing Manager), Media Specialist, Ads Optimizer, Content Creator, Facilitator, Secretary.  KPI (Chỉ số đo lường): Tổng số lượng Lead mới hằng tháng, Chi phí trên một Lead (CPL), Tỷ lệ Lead đạt tiêu chuẩn chất lượng (Qualified Lead Rate).Meeting Rhythm (Nhịp họp): Daily Huddle (15 phút), Weekly Tactical Meeting (60 phút), Monthly S.T.A.R.S Review (90 phút).  Governance / Decision Rules (Quy tắc quyết định): Tự chủ quyết định phân bổ ngân sách trong hạn mức hằng tháng đã phê duyệt; mọi đề xuất thay đổi định hướng nội dung lớn ảnh hưởng đến hình ảnh thương hiệu lõi phải thực hiện thủ tục xin Consent từ Core Circle.','growth-circle-vong-tron-tang-truong-thu-hut-au-pheu-purpose-muc-tieu-xay-dung-ta',55,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef903fee-0960-4976-a2ee-a093ddfd0ce4','74e21e61-449b-4dba-bf35-f21f82b66f4a',92,'image',NULL,'book/07-phu-luc/aaed2811-48aa-4df1-93f8-59759d4d658a-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e9b5b648-ed3b-4381-8bc2-0e68fd8bb229','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'Patient Circle (Vòng tròn Trải nghiệm &amp; Chuyển đổi Khách hàng)','patient-circle-vong-tron-trai-nghiem-amp-chuyen-oi-khach-hang',56,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d00d287-7f4f-497f-9ded-b8e200b891b2','e9b5b648-ed3b-4381-8bc2-0e68fd8bb229',93,'text','Được tiếp nhận toàn bộ phần inbox, đặt lịch, tư vấn, show-up, chăm sóc và hệ sinh thái referral để tránh chồng lấn.  - **Purpose (Mục tiêu):** Tối ưu hóa tỷ lệ chuyển đổi từ Lead thành lịch hẹn, xây dựng hành trình trải nghiệm khách hàng xuất sắc tại phòng khám, duy trì tỷ lệ tái khám và kích hoạt hệ sinh thái giới thiệu (Referral).  - **Domain (Miền kiểm soát):** Hệ thống CRM, Hộp thư tiếp nhận (Inbox/Hotline), Kịch bản tư vấn và chăm sóc khách hàng, Không gian trải nghiệm trực tiếp tại phòng khám, Cơ sở dữ liệu khách hàng cũ.  - **Accountabilities (Trách nhiệm giải trình):** Trực và xử lý dữ liệu inbox/hotline để chốt lịch hẹn (Booking); tối ưu tỷ lệ khách đến phòng khám (Show-up); thực hiện quy trình tư vấn trực tiếp và chốt kế hoạch điều trị (Case Acceptance); chăm sóc khách hàng sau điều trị; quản lý lịch tái khám định kỳ; thu thập đánh giá (Review) và vận hành cơ chế khách giới thiệu khách (Referral Ecosystem).  - **Roles (Vai trò cốt lõi):** Circle Lead (Clinic Manager hoặc Trưởng bộ phận CSKH), Tele-sales/Booking Specialist, Consultant (Tư vấn viên), Receptionist (Lễ tân), Customer Care Specialist.  - **KPI (Chỉ số đo lường):** Tỷ lệ đặt hẹn thành công (Lead-to-Book Rate), Tỷ lệ khách đến khám (Show-up Rate), Tỷ lệ đồng ý điều trị (Case Acceptance Rate), Điểm số đo lường mức độ hài lòng giới thiệu (NPS), Tỷ lệ khách quay lại (Retention Rate).  - **Meeting Rhythm (Nhịp họp):** Daily Huddle (15 phút), Weekly Tactical Meeting (90 phút), Monthly Governance Meeting (60 phút).  - **Governance / Decision Rules (Quy tắc quyết định):** Tự chủ tối ưu hóa kịch bản chốt sales và quy trình chăm sóc trong phạm vi SOP; các chương trình ưu đãi hoặc chính sách chiết khấu đặc biệt vượt khung quy định phải thực hiện Escalation lên Core Circle hoặc Finance & Data Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f98a622-d872-4229-8eea-878a7da8ea28','e9b5b648-ed3b-4381-8bc2-0e68fd8bb229',94,'image',NULL,'book/07-phu-luc/bec9d2dc-7429-4f13-91a5-66d105532d91-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('08846e2c-97d4-4c80-8db1-c5525981ea80','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'Clinical Circle (Vòng tròn Chuyên môn Lâm sàng)','clinical-circle-vong-tron-chuyen-mon-lam-sang',57,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7c53238-2c9a-4343-8d5a-62752c349849','08846e2c-97d4-4c80-8db1-c5525981ea80',95,'text','Giữ ranh giới thuần túy chuyên môn, y khoa và hiệu suất vận hành lâm sàng.  - **Purpose (Mục tiêu):** Thực thi các dịch vụ khám, chẩn đoán và điều trị chuẩn y khoa; đảm bảo an toàn lâm sàng tuyệt đối và tối ưu hóa hiệu suất khai thác phòng khám.  - **Domain (Miền kiểm soát):** Hệ thống phòng điều trị, Khu vực vô khuẩn, Trang thiết bị và vật tư y tế, Hồ sơ bệnh án của bệnh nhân, Quy trình bàn giao lâm sàng (Handover).  - **Accountabilities (Trách nhiệm giải trình):** Chịu trách nhiệm toàn diện về chất lượng điều trị lâm sàng; kiểm soát và thực thi nghiêm túc quy trình vô khuẩn khép kín; cập nhật và lưu trữ hồ sơ bệnh án chuẩn xác; thực hiện bàn giao thông tin bệnh nhân rõ ràng cho bộ phận chăm sóc (Handover); quản lý và bảo trì trang thiết bị y tế.  - **Roles (Vai trò cốt lõi):** Circle Lead (Bác sĩ trưởng), Bác sĩ điều trị chuyên sâu, Điều dưỡng trưởng, Phụ tá nha khoa.  - **KPI (Chỉ số đo lường):** Tỷ lệ ca điều trị an toàn (không xảy ra tai biến y khoa), Tỷ lệ tuân thủ SOP vô khuẩn, Hiệu suất khai thác ghế nha (Chair Utilization Rate), Tỷ lệ up-sell kế hoạch điều trị toàn diện hợp lý tại ghế.- **Meeting Rhythm (Nhịp họp):** Weekly Clinical Review (60 phút), Monthly Governance Meeting (60 phút).  - **Governance / Decision Rules (Quy tắc quyết định):** Bác sĩ trưởng có thẩm quyền tối cao về mặt chuyên môn lâm sàng; việc thay đổi danh mục vật liệu tiêu hao hoặc lựa chọn nhà cung cấp vật tư y tế mới phải thông qua Consent của Finance & Data Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9505e4bc-8ea8-41fb-b48b-f9e710ccdbcd','08846e2c-97d4-4c80-8db1-c5525981ea80',96,'image',NULL,'book/07-phu-luc/6004a2b1-4bce-4f32-b080-997614839723-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8305ecab-5dc3-4f7e-a519-4e52993e1b70','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'Finance &amp; Data Circle (Vòng tròn Tài chính &amp; Dữ liệu)','finance-amp-data-circle-vong-tron-tai-chinh-amp-du-lieu',58,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('074c7c3c-4161-4f17-978d-f313fb733d13','8305ecab-5dc3-4f7e-a519-4e52993e1b70',97,'text','Đóng vai trò cung cấp dữ liệu đối xứng, không tham gia quyết định chiến lược thay Core Circle.  - **Purpose (Mục tiêu):** Đảm bảo tính minh bạch, an toàn của dòng tiền; tối ưu hóa cấu trúc chi phí và cung cấp hệ thống báo cáo số liệu (Dashboard) thời gian thực phục vụ việc ra quyết định.  - **Domain (Miền kiểm soát):** Hệ thống phần mềm quản lý tổng thể (ERP/Dental Software), Dữ liệu tài chính kế toán, Tài khoản ngân hàng và két sắt phòng khám, Hệ thống Dashboard đo lường của toàn bộ các Circle.  - **Accountabilities (Trách nhiệm giải trình):** Quản lý thu chi, dòng tiền, công nợ khách hàng và nhà cung cấp; kiểm toán và chi trả lương thưởng dựa trên khung năng lực và hiệu suất(); kiểm soát định mức chi phí vận hành phòng khám; xây dựng và duy trì tính chính xác của các Dashboard chỉ số cho toàn hệ thống.  - **Roles (Vai trò cốt lõi):** Circle Lead (Kế toán trưởng / Trưởng bộ phận Tài chính), Thủ quỹ, Thu ngân, Data Analyst (Phân tích dữ liệu).  - **KPI (Chỉ số đo lường):** Độ chính xác và thời gian hoàn thành của báo cáo tài chính/dữ liệu (đạt 100%), Tỷ lệ chi phí vận hành trên doanh thu (OPEX Rate), Dòng tiền tự do (Free Cash Flow).- **Meeting Rhythm (Nhịp họp):** Weekly Tactical Meeting (60 phút), Monthly Financial & STARS Audit Review (120 phút).  - **Governance / Decision Rules (Quy tắc quyết định):** Có thẩm quyền phủ quyết (Veto) các đề xuất chi tiêu của các Circle khác nếu vượt định mức hoặc gây rủi ro cho dòng tiền; việc thay đổi công thức tính lương thưởng bắt buộc phải có Consent từ Core Circle và People & Culture Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82023535-9d39-4bd6-aaab-98bd9a87f04a','8305ecab-5dc3-4f7e-a519-4e52993e1b70',98,'image',NULL,'book/07-phu-luc/ffae7c0c-1352-4a4f-b9f8-b33efd6ceb42-img17.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fb9e8316-2075-474f-a601-d7cd21bd50a8','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'People &amp; Culture Circle (Vòng tròn Con người &amp; Văn hóa)','people-amp-culture-circle-vong-tron-con-nguoi-amp-van-hoa',59,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9b83f6f-a3f4-4270-aa96-c7105331866c','fb9e8316-2075-474f-a601-d7cd21bd50a8',99,'text','Tập trung vào role clarity và năng lực dựa trên nền tảng S.T.A.R.S People OS.  - **Purpose (Mục tiêu):** Thu hút, phát triển năng lực đội ngũ theo chuẩn `S.T.A.R.S` và duy trì nền tảng văn hóa phối hợp nội bộ lành mạnh.  - **Domain (Miền kiểm soát):** Quy trình tuyển dụng, Hệ thống tài liệu đào tạo nội bộ (LMS), Khung đánh giá năng lực `S.T.A.R.S`, Các hoạt động gắn kết văn hóa nội bộ.  - **Accountabilities (Trách nhiệm giải trình):** Thực hiện chiến dịch tuyển dụng và Onboarding nhân sự mới; điều phối quy trình đánh giá hiệu suất hằng tháng (`S.T.A.R.S Review`); xây dựng tài liệu và tổ chức đào tạo SOP nội bộ; giải quyết các xung đột nội bộ về mặt con người; lan tỏa các giá trị văn hóa phối hợp hệ thống.  - **Roles (Vai trò cốt lõi):** Circle Lead (Trưởng phòng Nhân sự), Recruiter (Chuyên viên tuyển dụng), Trainer (Chuyên viên đào tạo SOP), Culture Coordinator (Điều phối viên văn hóa).  - **KPI (Chỉ số đo lường):** Tỷ lệ hoàn thành kế hoạch tuyển dụng đúng hạn, Tỷ lệ giữ chân nhân sự (Retention Rate), Tỷ lệ hoàn thành đào tạo và đạt kiểm tra SOP nội bộ, Chỉ số hài lòng nội bộ (eNPS).- **Meeting Rhythm (Nhịp họp):** Weekly Tactical Meeting (60 phút), Monthly Governance & STARS Evaluation Meeting (90 phút).  - **Governance / Decision Rules (Quy tắc quyết định):** Tự chủ quyết định quy trình phỏng vấn và các phương pháp truyền thông nội bộ; việc ban hành hoặc sửa đổi khung năng lực cốt lõi hoặc thay đổi cơ cấu nhân sự cấp quản lý phải tiến hành Escalation lên Core Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d94db82-de3c-4206-b707-de603301dfba','fb9e8316-2075-474f-a601-d7cd21bd50a8',100,'image',NULL,'book/07-phu-luc/324ca515-d7bc-48e3-9e6d-26e0bd5d9346-img18.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1dac2809-a8bf-4bc1-9d10-baf21e11d0f8','07-phu-luc','4c02eb56-fce1-4468-b5ac-47040096417d',2,'HƯỚNG DẪN GHI NHẬN GOVERNANCE LOGBOOK CHO ĐỘI NGŨ','huong-dan-ghi-nhan-governance-logbook-cho-oi-ngu',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15272ed9-68f5-489d-a767-8b3fccf07496','1dac2809-a8bf-4bc1-9d10-baf21e11d0f8',101,'text','Mọi thay đổi phát sinh từ vận hành thực tế bắt buộc phải được ghi lại trong Sổ tay quản trị (Governance Logbook) theo nguyên tắc sau để duy trì tính nhất quán hệ thống:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7dc24a2d-1a02-43b7-aa70-7c7272d7f18e','1dac2809-a8bf-4bc1-9d10-baf21e11d0f8',102,'text','- **Policy Change (Thay đổi chính sách):** Khi một Circle đề xuất ban hành quy định biên giới mới, Thư ký ghi nhận dưới dạng: *[Mã số Policy] - [Nội dung quy tắc] - [Ngày thông qua Consent]*.  - **Role Change (Thay đổi nhân sự giữ vai trò):** Khi Circle Lead phân bổ lại nhân sự nắm giữ Vai trò (Role), Logbook cập nhật trực tiếp tên nhân sự tương ứng vào cấu trúc, không thay đổi mô tả nhiệm vụ của vai trò đó().  - **Tension Logging (Nhật ký xung đột):** Nhân sự gặp điểm nghẽn phải ghi nhận Tension theo định dạng: *[Vai trò gặp nghẽn] - [Thực trạng bất cập] - [Đề xuất hướng xử lý (Proposal)]* trước khi đưa vào chương trình họp định kỳ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ca2bd68f-e06c-4fc2-a2b2-8d8e38f95968','07-phu-luc',NULL,1,'7.4 EMPIRE CIRLE VÀ R.O.A.D.M.A.P','74-empire-cirle-va-roadmap',61,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6ddc58bc-b40d-46a3-8c21-ea9421455cb7','07-phu-luc','ca2bd68f-e06c-4fc2-a2b2-8d8e38f95968',2,'TỔNG QUAN LOGIC TÍCH HỢP: THỜI GIAN VS KHÔNG GIAN','tong-quan-logic-tich-hop-thoi-gian-vs-khong-gian',62,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e35dd1c-dec6-4c28-a21a-06931d856a68','6ddc58bc-b40d-46a3-8c21-ea9421455cb7',103,'text','- **R.O.A.D.M.A.P trả lời câu hỏi "KHI NÀO VÀ ĐI ĐÂU?":**định hướng cho tổ chức biết mình đang ở giai đoạn tiến hóa nào (Từ việc tìm Bản sắc ở tầng *Root*, tích lũy năng lực ở tầng *Deepen*, cho đến khi tự vận hành ở tầng *Mature*).  - **Circle Map trả lời câu hỏi "AI LÀM VÀ QUYỀN ĐẾN ĐÂU?":** Bản chất là một cấu trúc phẳng, phi tập trung quyền lực để xử lý công việc hằng ngày dựa trên các biên giới (Domain) rõ ràng().',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('417ac291-5623-428b-9e0a-83950a8d9ad3','6ddc58bc-b40d-46a3-8c21-ea9421455cb7',104,'text','**Sự hợp lý cốt lõi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8cf0fcb7-0b85-4b0c-883e-cff9dcb9f76f','6ddc58bc-b40d-46a3-8c21-ea9421455cb7',105,'text','Nếu chỉ có R.O.A.D.M.A.P, chiến lược của Founder sẽ mãi là một "Manifesto" truyền động lực trên giấy vì thiếu bộ máy thực thi. Ngược lại, nếu chỉ có Circle, các vòng tròn tự chủ sẽ như những chiến binh mất phương hướng, tự vận hành theo ý mình và dễ dẫn đến tình trạng vỡ trận do chồng lấn mục tiêu. Sự kết hợp này nắn dòng năng lượng tự chủ của các Circle đi đúng theo lộ trình tăng trưởng của tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4e5c6ea9-6575-4e1f-ae78-27521614bc76','07-phu-luc','ca2bd68f-e06c-4fc2-a2b2-8d8e38f95968',2,'ÁNH XẠ CHI TIẾT: R.O.A.D.M.A.P KÍCH HOẠT VÀ TIẾN HÓA CIRCLE RA SAO?','anh-xa-chi-tiet-roadmap-kich-hoat-va-tien-hoa-circle-ra-sao',63,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24b6fbc2-6195-4221-80b7-56492e0b073a','4e5c6ea9-6575-4e1f-ae78-27521614bc76',106,'text','Bản ánh xạ này đồng bộ hóa **Trục tiến hóa chiến lược (R.O.A.D.M.A.P)** và **Trục thực thi phân quyền (Kiến trúc 5+1 Circle)** của hệ điều hành `Dental Empire OS`. Sự tích hợp này đảm bảo hệ thống tự chủ Circle luôn vận hành có định hướng, bám sát từng giai đoạn trưởng thành của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f8c8a49f-e82f-4cc3-8eb3-79f2be3987e9','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'R - ROOTS (Gốc Rễ Bản Sắc): Nạp Mã Gen cho Core Circle','r-roots-goc-re-ban-sac-nap-ma-gen-cho-core-circle',64,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b428d2f-0dc8-4359-89fe-41dc6209cb1b','f8c8a49f-e82f-4cc3-8eb3-79f2be3987e9',107,'text','- **Mục tiêu chiến lược:** Xác lập DNA Statement, định vị thương hiệu lõi, chân dung khách hàng mục tiêu và các giá trị văn hóa không thỏa hiệp (SKY Culture).  - **Ánh xạ cấu trúc Circle:** Nội dung tầng Root chính là nội dung nền tảng thuộc **Domain (Miền kiểm soát độc quyền)** của **Core Circle**.  - **Cơ chế vận hành:** Core Circle có trách nhiệm bảo vệ và sử dụng bộ mã gen Root này để làm màng lọc tối cao cho mọi chính sách (Policy) được ban hành hoặc gán quyền lực xuống các Circle con.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('835db232-4a8d-40e2-9fd6-70c9c29831fe','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'O - ONE LIGHT (Một Nguồn Sáng / Sự Minh Bạch): Kích hoạt Hệ thống Cảm biến Dữ liệu','o-one-light-mot-nguon-sang-su-minh-bach-kich-hoat-he-thong-cam-bien-du-lieu',65,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54117e76-956a-48e8-8766-049a499e2acf','835db232-4a8d-40e2-9fd6-70c9c29831fe',108,'text','- **Mục tiêu chiến lược:** Đưa toàn bộ số liệu, thực trạng vận hành và hành trình khách hàng ra ánh sáng. Chấm dứt hoàn toàn tình trạng quản trị cảm tính hoặc ra quyết định trong bóng tối.  - **Ánh xạ cấu trúc Circle:** Đây là giai đoạn bàn giao Domain về Dữ liệu và thiết lập công cụ đối xứng thông tin cho các Circle:  *Growth Circle* nhận ánh sáng từ số liệu quảng cáo và dữ liệu Lead đầu phễu.  - *Patient Circle* quản trị hệ thống CRM tập trung (nguồn lưu trữ lịch sử tương tác khách hàng).  - *Finance & Data Circle* chịu trách nhiệm tối cao trong việc duy trì tính chính xác 100% của các Real-time Dashboard toàn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c579df32-4834-4115-a20b-8bd0ec0801c8','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'A - AWAKEN (Tỉnh Thức Để Đổi Mới): Chuyển hóa Dữ liệu thành Nhiên liệu "Tension"','a-awaken-tinh-thuc-e-oi-moi-chuyen-hoa-du-lieu-thanh-nhien-lieu-tension',66,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8159df0b-3ab9-40cc-b0c1-5bd33350bc83','c579df32-4834-4115-a20b-8bd0ec0801c8',109,'text','- **Mục tiêu chiến lược:** Sử dụng các công cụ tự kiểm toán (Self-audit S.T.A.R.S) để nhận diện khoảng cách giữa mục tiêu chiến lược và thực tế, định vị chính xác các điểm nghẽn nội tại.  - **Ánh xạ cấu trúc Circle:** Trong ngữ pháp S3, điểm nghẽn chính là **Tension**.  - **Cơ chế vận hành:** Tầng Awaken yêu cầu nhân sự giữ vai trò ở các Circle (Growth, Patient, Clinical...) chủ động quan sát thực tế để ghi nhận các Tension vận hành. Các Tension này được tập hợp và đưa vào danh mục xử lý (Triage Tensions) trong nhịp họp *Weekly Tactical* hằng tuần để biến thành hành động cải tiến.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c0f0ae04-02c5-4d87-865e-0db2e0451faf','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'D - DEEPEN (Đào Sâu Năng Lực): Chuẩn hóa Accountability và Đóng gói SOP','d-deepen-ao-sau-nang-luc-chuan-hoa-accountability-va-ong-goi-sop',67,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6eb5aa2d-7c80-4eeb-b8a0-dd844b558347','c0f0ae04-02c5-4d87-865e-0db2e0451faf',110,'text','- **Mục tiêu chiến lược:** Tập trung đào sâu năng lực nội tại, tối ưu hóa quy trình, siết chặt kỷ luật và làm chắc nền tảng vận hành mang tính cấu trúc.  - **Ánh xạ cấu trúc Circle:** Định hình chi tiết cấu trúc bên trong của từng Role (Vai trò) trong Circle thông qua **Accountability (Trách nhiệm giải trình)**.  - **Cơ chế vận hành:** Các Circle tiến hành đóng gói quy trình thành văn bản chuẩn: *Clinical Circle* chuẩn hóa SOP vô khuẩn và checklist chuẩn bị Implant/Chỉnh nha; *Patient Circle* chuẩn hóa kịch bản tư vấn và follow-up(). Mỗi nhân sự nắm giữ Role Card phải cam kết năng lực thực thi dựa trên các SOP đã được làm sâu ở tầng này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16903d9d-df0c-4d2c-abb7-2498c58ae745','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'M - MATURE (Trưởng Thành &amp; Ổn Định): Vận hành Hệ thống Tự chủ bằng Logbook và Consent','m-mature-truong-thanh-amp-on-inh-van-hanh-he-thong-tu-chu-bang-logbook-va-consen',68,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71188731-7352-4b4e-9152-a2a70698100f','16903d9d-df0c-4d2c-abb7-2498c58ae745',111,'text','- **Mục tiêu chiến lược:** Đưa phòng khám vượt qua tính ngẫu nhiên, đạt độ ổn định cao và có khả năng tự vận hành bằng hệ thống chứ không phụ thuộc vào cá nhân Founder.  - **Ánh xạ cấu trúc Circle:** Kích hoạt toàn diện các công cụ điều hành tối cao của mô hình `S3 Holacracy Lite`.  - **Cơ chế vận hành:**Mọi cấu trúc, vai trò, nhân sự kiêm nhiệm và chính sách của phòng khám bắt buộc phải được chuẩn hóa tại **Governance Logbook**.  - Các Circle tự chủ đưa ra quyết định thay đổi nội bộ thông qua cơ chế lấy **Consent** (Đồng thuận dựa trên nguyên tắc: Đề xuất được thông qua nếu không có phản đối gây hại cho tổ chức). Founder hoàn toàn được giải phóng khỏi các sự vụ điều hành chi tiết.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f35147fd-b8f0-4371-8d73-28462e51c5ad','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'A - ALIGN (Đồng Bộ Mục Tiêu): Thiết lập Mạng lưới Rep Link Chống Cát Cứ','a-align-ong-bo-muc-tieu-thiet-lap-mang-luoi-rep-link-chong-cat-cu',69,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1273125d-3aba-495c-be58-37bc31291b85','f35147fd-b8f0-4371-8d73-28462e51c5ad',112,'text','- **Mục tiêu chiến lược:** Đồng bộ hóa con người, vai trò, mục tiêu chiến lược và văn hóa để toàn bộ hệ thống cùng đi chung một hướng, triệt tiêu xung đột nội bộ.  - **Ánh xạ cấu trúc Circle:** Vận hành cơ chế kết nối đa chiều giữa các Circle độc lập để tránh bẫy "Silo cục bộ" (các phòng ban tự cô lập thông tin).- **Cơ chế vận hành:** Sử dụng vai trò cấu trúc **Rep Link (Kết nối đại diện)** được bầu từ các Circle con để mang tiếng nói, đề xuất hoặc các xung đột liên Circle lên Core Circle xử lý. Đồng thời, ghép nối các mục tiêu ngắn hạn của từng Circle vào quỹ đạo chung thông qua phương pháp OKRs tổng và các Theme trọng tâm theo quý().',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('31eb5e38-2b68-4740-9103-637644d682cb','07-phu-luc','4e5c6ea9-6575-4e1f-ae78-27521614bc76',3,'P - PROSPER (Thịnh Vượng): Kích hoạt Hiệu ứng Tăng trưởng Kép từ Bánh đà Tự chạy','p-prosper-thinh-vuong-kich-hoat-hieu-ung-tang-truong-kep-tu-banh-a-tu-chay',70,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e83a171d-4f9c-4538-b08b-1fde17896a64','31eb5e38-2b68-4740-9103-637644d682cb',113,'text','- **Mục tiêu chiến lược:** Đạt tới trạng thái sinh sôi, thịnh vượng bền vững; tạo ra năng lượng thặng dư và đa dòng chảy giá trị để hệ thống tự nuôi sống chính nó.  - **Ánh xạ cấu trúc Circle:** Giai đoạn tối ưu hóa hiệu suất của toàn bộ các khối Circle con khi tất cả các bánh răng đã khớp hoàn toàn.- **Cơ chế vận hành:** Khi *Growth Circle* tối ưu chi phí Lead đầu phễu, *Clinical Circle* tối ưu hiệu suất ghế nha, *Patient Circle* vận hành trơn tru hệ sinh thái giới thiệu (Referral), và *Finance & Data Circle* kiểm soát tốt định mức chi phí phòng khám sẽ tạo ra dòng tiền thặng dư an toàn. Core Circle dựa trên nguồn lực này để đưa ra các quyết định mở rộng quy mô, nghiên cứu đa tầng sản phẩm (Product Layer) hoặc nhân bản chuỗi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('31a327e5-a048-499a-bf9e-39674d9c3483','07-phu-luc','ca2bd68f-e06c-4fc2-a2b2-8d8e38f95968',2,'TÓM TẮT GIÁ TRỊ THỰC CHIẾN','tom-tat-gia-tri-thuc-chien',71,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1cd112c5-8e37-404a-8c7d-44769cfec0a2','31a327e5-a048-499a-bf9e-39674d9c3483',114,'text','Sự kết hợp này mang lại cho phòng khám nha khoa **"Kiến trúc thích nghi hữu cơ"**: Vừa có sự linh hoạt, tốc độ phản ứng nhanh của các nhóm tự chủ ở mặt trận hằng ngày (Circle), vừa có sự nhất quán, kiên định về tầm nhìn dài hạn ở tầng thượng tầng (R.O.A.D.M.A.P).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dea71f1f-7cbf-46d8-845f-7197af735c3c','31a327e5-a048-499a-bf9e-39674d9c3483',115,'text','Bước đầu tiên để đưa hệ thống tự chủ vào thực tế là bóc tách và chuẩn hóa **Bước 1: Quy trình bàn giao và Biên giới động (Cross-Circle Handover Funnel)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('015680ee-9e3c-49ea-a7f8-8e334267fc5f','31a327e5-a048-499a-bf9e-39674d9c3483',116,'text','Quy trình này định nghĩa chính xác cách dữ liệu và con người di chuyển qua ranh giới giữa năm khối Circle chuyên môn(), thiết lập các cam kết thời gian phản hồi (SLA) để đảm bảo không một thông tin nào bị rơi vào "góc tối" (tuân thủ nguyên tắc **One Light**).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f7466f3f-3545-49bf-b10e-2f0ccd6a0303','07-phu-luc',NULL,1,'7.5 QUY TRÌNH BÀN GIAO VÀ BIÊN GIỚI ĐỘNG (CROSS-CIRCLE HANDOVER FUNNEL)','75-quy-trinh-ban-giao-va-bien-gioi-ong-cross-circle-handover-funnel',72,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('017518b4-b878-4efd-9287-ee1c07dc1de5','f7466f3f-3545-49bf-b10e-2f0ccd6a0303',117,'image',NULL,'book/07-phu-luc/6a1b2def-7f7b-44b4-a8ae-afb3efba91a8-img19.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4d350ab0-8f5c-49aa-8c44-7654bccf9a7f','07-phu-luc','f7466f3f-3545-49bf-b10e-2f0ccd6a0303',2,'Growth Circle -&gt; Patient Circle (Bàn giao Dữ liệu Khách hàng Mới)','growth-circle-gt-patient-circle-ban-giao-du-lieu-khach-hang-moi',73,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cd945e4-764d-4500-8d06-2df4b22e33fa','4d350ab0-8f5c-49aa-8c44-7654bccf9a7f',118,'text','Điểm chạm biên giới giữa khối truyền thông/thu hút đầu phễu và khối xử lý inbox/hotline/đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db974b37-85c1-4e21-abcb-0c12c1e6a151','4d350ab0-8f5c-49aa-8c44-7654bccf9a7f',119,'text','- **Tiêu chuẩn dữ liệu đầu ra (Handover Data):** Thông tin Lead đổ về CRM bắt buộc phải có: Họ tên, Số điện thoại, Nhu cầu điều trị tự khai, Kênh tiếp cận (Ads/SEO/Media Network), và Mã ưu đãi (nếu có).  - **Cam kết thời gian phản hồi (SLA):** Trong giờ hành chính, kể từ khi Lead xuất hiện trên hệ thống CRM, vai trò *Tele-sales/Booking Specialist* thuộc Patient Circle phải thực hiện cuộc gọi hoặc nhắn tin đầu tiên cho khách hàng trong vòng **tối đa 15 phút**.  - **Cơ chế xử lý Tension:** Nếu quá 15 phút hệ thống ghi nhận Lead chưa được xử lý, CRM tự động bắn cảnh báo Tension về hiệu suất vận hành cho Circle Lead của Patient Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e924dbdc-9e43-4ab3-b380-cffe523693fc','07-phu-luc','f7466f3f-3545-49bf-b10e-2f0ccd6a0303',2,'Patient Circle -&gt; Clinical Circle (Bàn giao Bệnh nhân Đến Khám)','patient-circle-gt-clinical-circle-ban-giao-benh-nhan-en-kham',74,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('180b3f3a-4d25-464d-8395-781d85aceba1','e924dbdc-9e43-4ab3-b380-cffe523693fc',120,'text','Điểm chạm biên giới từ lúc Lễ tân check-in cho khách tại phòng khám cho đến khi khách bước vào ghế điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04f50e64-31e1-4df4-9f54-df74f0945131','e924dbdc-9e43-4ab3-b380-cffe523693fc',121,'text','- **Tiêu chuẩn dữ liệu đầu ra (Handover Data):** Hồ sơ điện tử của khách hàng được cập nhật trạng thái "Đã đến" (Show-up), đính kèm: Lịch sử tư vấn online, mong muốn cốt lõi, mức ngân sách dự kiến, và lưu ý đặc biệt về tâm lý (ví dụ: sợ đau, sợ tiếng ồn).  - **Cam kết thời gian phản hồi (SLA):** Kể từ khi Lễ tân hoàn thành check-in và chuyển trạng thái trên CRM, bộ phận Điều dưỡng trưởng thuộc Clinical Circle phải điều phối Phụ tá chuẩn bị phòng máy và gán Bác sĩ điều trị trong vòng **tối đa 3 phút**.  - **Cơ chế xử lý Tension:** Khách hàng không phải ngồi chờ tại sảnh quá 10 phút mà không có lý do chuyên môn giải thích trước. Nếu quá giờ, vai trò *Receptionist* có quyền yêu cầu *Điều dưỡng trưởng* giải trình điểm nghẽn tại ghế lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e34cc1b8-8b7c-4506-8229-3a27b818b635','07-phu-luc','f7466f3f-3545-49bf-b10e-2f0ccd6a0303',2,'Clinical Circle -&gt; Patient Circle (Bàn giao Hậu phẫu &amp; Chăm sóc)','clinical-circle-gt-patient-circle-ban-giao-hau-phau-amp-cham-soc',75,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa05225a-e147-4a20-891d-e32cf6f808ad','e34cc1b8-8b7c-4506-8229-3a27b818b635',122,'text','Điểm chạm biên giới từ khi bệnh nhân bước ra khỏi ghế điều trị lâm sàng quay trở lại quy trình chăm sóc và thu thập đánh giá.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce844c42-20fc-428e-b25e-7c27608eee4d','e34cc1b8-8b7c-4506-8229-3a27b818b635',123,'text','- **Tiêu chuẩn dữ liệu đầu ra (Handover Data):** Bác sĩ hoặc Phụ tá ghi nhận đầy đủ "Clinical Notes" vào bệnh án điện tử: Thủ thuật đã làm, Đơn thuốc được kê, Tình trạng răng thực tế sau ca, Chỉ định dặn dò đặc biệt từ Bác sĩ, và Lịch hẹn tái khám cụ thể (ngày/giờ).  - **Cam kết thời gian phản hồi (SLA):** Toàn bộ Clinical Notes phải được lưu vết trên hệ thống **tối đa 5 phút** sau khi bệnh nhân rời ghế điều trị (bắt buộc phải hoàn thành trước khi bệnh nhân bước ra quầy Thu ngân).  - **Cơ chế xử lý Tension:** Vai trò *Customer Care Specialist* dựa vào đúng Clinical Notes này để kích hoạt kịch bản gọi điện kiểm tra sau 24 giờ. Nếu Bác sĩ không cập nhật ghi chú chuyên môn, bộ phận Chăm sóc khách hàng có quyền từ chối gọi điện vì thiếu dữ liệu y khoa và chuyển Tension này lên *Bác sĩ trưởng*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0921ace1-09af-4100-a4a2-c64514d4c572','07-phu-luc','f7466f3f-3545-49bf-b10e-2f0ccd6a0303',2,'Các Circle -&gt; Finance &amp; Data Circle (Bàn giao Dữ liệu Tài chính &amp; Chỉ số)','cac-circle-gt-finance-amp-data-circle-ban-giao-du-lieu-tai-chinh-amp-chi-so',76,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e03bbc52-063c-4862-93a1-63dcce2eaf1c','0921ace1-09af-4100-a4a2-c64514d4c572',124,'text','Trục đối xứng thông tin hằng ngày đảm bảo toàn bộ hệ thống vận hành dưới một nguồn sáng dữ liệu chuẩn xác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50312e60-567a-406b-93ea-93a6618f1208','0921ace1-09af-4100-a4a2-c64514d4c572',125,'text','- **Tiêu chuẩn dữ liệu đầu ra (Handover Data):***Patient Circle (Thu ngân):* Báo cáo tổng số tiền thực thu, phân loại theo hình thức thanh toán (Tiền mặt/Chuyển khoản/Quẹt thẻ/Trả góp).  - *Growth Circle (Ads Optimizer):* Số liệu ngân sách chi tiêu quảng cáo thực tế trong ngày.  - *Clinical Circle (Điều dưỡng trưởng):* Phiếu xuất kho vật liệu tiêu hao và labo sử dụng trong ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ee593a1-660b-42c3-a89b-fa9fd83227bf','0921ace1-09af-4100-a4a2-c64514d4c572',126,'text','Quy trình bàn giao 4 đoạn này sẽ khóa chặt toàn bộ dòng chảy vận hành của phòng khám, không cho phép các bộ phận đùn đẩy trách nhiệm vì ranh giới quyền hạn và thời gian xử lý đã được định rõ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4381f656-70e1-4b8d-8831-e006a4260eaf','0921ace1-09af-4100-a4a2-c64514d4c572',127,'text','Khi phòng khám vận hành theo mô hình tự chủ **Circle (S3 Holacracy Lite)**, rào cản lớn nhất khiến các cuộc họp bị tắc nghẽn là tình trạng nhân sự đưa ra các phản đối dựa trên cảm tính, thói quen cũ hoặc nỗi sợ mơ hồ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('55430068-e6b3-4325-9e00-4523bfc6587d','07-phu-luc',NULL,1,'7.6 BỘ TIÊU CHÍ KIỂM TRA "PHẢN ĐỐI HỢP LỆ" (OBJECTION TEST)','76-bo-tieu-chi-kiem-tra-phan-oi-hop-le-objection-test',77,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cca7a532-9469-4e67-a512-0f50a80cc651','07-phu-luc','55430068-e6b3-4325-9e00-4523bfc6587d',2,'Phân biệt "Ý kiến cá nhân" (Opinion) và "Phản đối hợp lệ" (Objection)','phan-biet-y-kien-ca-nhan-opinion-va-phan-oi-hop-le-objection',78,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e3a7d1eb-a216-4700-a7d3-62896bba88c4','cca7a532-9469-4e67-a512-0f50a80cc651',128,'text','Trong một cuộc họp của Circle, nhân sự rất dễ nhầm lẫn giữa việc đóng góp góc nhìn cá nhân và việc chặn một quy trình. Người điều phối cần làm rõ biên giới:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a28cea3b-a83d-4b93-ab90-5869e8ab6b39','cca7a532-9469-4e67-a512-0f50a80cc651',129,'text','- **Ý kiến cá nhân (Opinion):** Là những nhận xét mang tính chủ quan, dựa trên sở thích, thói quen hoặc trải nghiệm cũ. Ý kiến cá nhân **không có quyền** dừng một đề xuất (Proposal).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('581a2a43-1d1d-4413-ad33-a50cdf7571ae','cca7a532-9469-4e67-a512-0f50a80cc651',130,'text','Ví dụ: *"Em thấy làm checklist này phiền phức lắm", "Em nghĩ khách hàng sẽ không thích khai báo thông tin dài dòng thế này đâu"*).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d327a42-fb2a-4275-8503-d75c959f9190','cca7a532-9469-4e67-a512-0f50a80cc651',131,'text','- **Phản đối hợp lệ (Objection):** Là một luận điểm có lý lẽ, dựa trên dữ liệu hoặc bằng chứng thực tế chứng minh rằng nếu thông qua đề xuất này, nó sẽ trực tiếp gây tổn hại hoặc làm lùi bước sự phát triển của phòng khám. Phản đối hợp lệ **bắt buộc** hệ thống phải dừng lại để điều chỉnh đề xuất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6fc73a6e-dc73-4546-b220-6904c92ebf34','07-phu-luc','55430068-e6b3-4325-9e00-4523bfc6587d',2,'Màng lọc 3 câu hỏi kiểm tra (Objection Test Matrix)','mang-loc-3-cau-hoi-kiem-tra-objection-test-matrix',79,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3496f0db-1c31-408d-a13b-1ecc813db7d4','6fc73a6e-dc73-4546-b220-6904c92ebf34',132,'text','Khi một thành viên trong Circle giơ tay đưa ra ý kiến phản đối đối với một đề xuất quy trình mới, *Facilitator* sẽ lập tức chạy **Objection Test** bằng cách yêu cầu người phản đối trả lời lần lượt 3 câu hỏi dưới đây. Nếu câu trả lời vi phạm bất kỳ câu hỏi nào, phản đối đó lập tức bị hủy bỏ và đề xuất được thông qua.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('652e663e-ea0c-476c-ac20-ea783d35c3ee','6fc73a6e-dc73-4546-b220-6904c92ebf34',133,'image',NULL,'book/07-phu-luc/275f9b67-f668-4880-9704-0a546c8ed545-img20.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b01369d5-e43a-455e-95ff-12eca2b9bd42','07-phu-luc','6fc73a6e-dc73-4546-b220-6904c92ebf34',4,'Câu 1: Tiêu chí Bằng chứng Tổn hại (Damage Evidence)','cau-1-tieu-chi-bang-chung-ton-hai-damage-evidence',80,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7e2490c-9c23-4e8f-97ed-ed7d96f5e1b3','b01369d5-e43a-455e-95ff-12eca2b9bd42',134,'text','- **Câu hỏi của Facilitator:** *"Bạn có bằng chứng thực tế hoặc dữ liệu nào chứng minh đề xuất này sẽ gây ra tổn hại trực tiếp cho phòng khám hoặc bệnh nhân không? Hay đây chỉ là sự suy đoán/nỗi sợ của cá nhân bạn?"* - **Nguyên tắc màng lọc:** Nếu người phản đối trả lời *"Em đoán là..."* hoặc *"Em sợ rằng..."* mà không chỉ ra được lỗ hổng dữ liệu, phản đối này không hợp lệ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6b9e3ee3-d0bd-450d-bb40-be1a6d0c99be','07-phu-luc','6fc73a6e-dc73-4546-b220-6904c92ebf34',4,'Câu 2: Tiêu chí Cản trở Mục tiêu (Purpose Hindrance)','cau-2-tieu-chi-can-tro-muc-tieu-purpose-hindrance',81,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1565a703-4c92-412b-b217-bd95dcfdba18','6b9e3ee3-d0bd-450d-bb40-be1a6d0c99be',135,'text','- **Câu hỏi của Facilitator:** *"Nếu áp dụng đề xuất này, nó có trực tiếp cản trở hoặc phá vỡ việc thực hiện Purpose (Mục tiêu tối thượng) của chính Circle này, hoặc của vai trò mà bạn đang nắm giữ không?"*- **Nguyên tắc màng lọc:** Đề xuất có thể gây bất tiện ngắn hạn cho nhân sự, nhưng nếu nó phục vụ tốt hơn cho dòng chảy khách hàng hoặc an toàn y khoa, và không vi phạm Purpose của Circle, thì phản đối không được chấp nhận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5113ad3e-3aff-4b72-8a52-966e1d0e34fc','07-phu-luc','6fc73a6e-dc73-4546-b220-6904c92ebf34',4,'Câu 3: Tiêu chí Đủ an toàn để thử (Safe to try)','cau-3-tieu-chi-u-an-toan-e-thu-safe-to-try',82,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8fa90f67-c524-4c4b-91da-750a4c4c79f3','5113ad3e-3aff-4b72-8a52-966e1d0e34fc',136,'text','- **Câu hỏi của Facilitator:** *"Đề xuất này có thực sự ''không an toàn để thử'' ngay lập tức không? Nếu chúng ta giới hạn thử nghiệm quy trình này trong vòng 2 tuần tại 1 ghế nha duy nhất để thu thập dữ liệu, nó có gây ra hậu quả nào không thể sửa chữa được hay không?"*- **Nguyên tắc màng lọc:** Nếu hậu quả của đề xuất có thể sửa sai được sau một chu kỳ thử nghiệm ngắn (Sprint), hệ thống sẽ chọn ưu tiên hành động thay vì ngồi bàn lùi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('af1c281b-5176-477d-a93e-b5fef0658360','07-phu-luc','55430068-e6b3-4325-9e00-4523bfc6587d',2,'Kịch bản xử lý thực tế của Người điều phối (Facilitator Script)','kich-ban-xu-ly-thuc-te-cua-nguoi-ieu-phoi-facilitator-script',83,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d3d9c67-b213-4d72-bd0f-de6903d4afdc','af1c281b-5176-477d-a93e-b5fef0658360',137,'text','Để duy trì "ngữ pháp hệ thống" văn minh và chuyên nghiệp, *Facilitator* sẽ điều phối theo kịch bản chuẩn sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e4b843c-427d-4a40-8282-49eb3cc68cc2','af1c281b-5176-477d-a93e-b5fef0658360',138,'text','💬 **Bối cảnh:** *Patient Circle* đang họp bàn đề xuất ban hành Policy: *"Mọi tin nhắn của khách hàng cũ quay lại tư vấn phải được lễ tân gán tag phân loại trên CRM trong vòng 5 phút."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3b66008-209c-4960-ae5c-d9b61e52f6d2','af1c281b-5176-477d-a93e-b5fef0658360',139,'text','()',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d44da233-f17b-4657-b7b4-17847d9a8f9b','af1c281b-5176-477d-a93e-b5fef0658360',140,'text','👤 **Nhân sự Lễ tân:** *"Em phản đối. Giờ cao điểm tụi em bận đón khách trực tiếp tại sảnh, vừa nghe điện thoại, làm sao kiểm tra CRM liên tục 5 phút một lần được. Áp dụng cái này tụi em không làm nổi."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('950344a5-71f7-401f-afd2-8ed05351011c','af1c281b-5176-477d-a93e-b5fef0658360',141,'text','()',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38fd2766-a268-4c6b-a6aa-5894b5f2065d','af1c281b-5176-477d-a93e-b5fef0658360',142,'text','🧠 **Facilitator thực hiện Objection Test:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34079eef-8f73-43c4-b54f-51615728ef8b','af1c281b-5176-477d-a93e-b5fef0658360',143,'text','- **Bước 1 (Kiểm tra Tiêu chí 1):** "Cảm ơn góc nhìn từ vai trò Lễ tân(). Cho mình hỏi, bạn có dữ liệu lịch sử nào về số lượng khách check-in cùng lúc vào giờ cao điểm để chứng minh quy tắc 5 phút này chắc chắn sẽ bị vỡ không?"  - *Lễ tân trả lời:* *"Dạ có, dữ liệu CRM tháng trước cho thấy từ 17h - 19h hằng ngày, trung bình có 8 ca show-up cùng lúc, lễ tân phải xử lý thủ tục liên tục."*() (-> Tiêu chí 1 đạt: Có bằng chứng cụ thể)().  - **Bước 2 (Kiểm tra Tiêu chí 2 & 3):** "Dữ liệu rất rõ ràng(). Vậy nếu chúng ta bổ sung một điều khoản phụ vào Policy này: ''Ngoại trừ khung giờ cao điểm từ 17h - 19h sẽ được gia hạn thành 20 phút'', thì đề xuất này đã đủ an toàn để chúng ta thử nghiệm (Safe to try) trong vòng 14 ngày tới chưa?"()  - *Lễ tân trả lời:* *"Nếu có khung giờ ngoại lệ đó thì tụi em kiểm soát được."*- **Bước 3 (Kết luận):** "Tuyệt vời. Như vậy phản đối đã được giải quyết bằng cách bổ sung điều khoản phụ(). Thư ký cập nhật bản sửa đổi này vào Governance Logbook. Đề xuất chính thức thông qua."()',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('588e6a06-c8db-4ed0-a350-95f06512a427','07-phu-luc','55430068-e6b3-4325-9e00-4523bfc6587d',2,'Bảng đối chiếu xử lý Tình huống lâm sàng tại Phòng khám','bang-oi-chieu-xu-ly-tinh-huong-lam-sang-tai-phong-kham',84,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f79bfb4d-3648-4100-bdb0-899cd9c8ed5c','588e6a06-c8db-4ed0-a350-95f06512a427',144,'text','Trong hệ điều hành **Dental Empire OS**, chúng ta bóc tách hoàn toàn "Con người" (Soul) ra khỏi "Công việc" (Role). Một nhân sự có thể nắm giữ nhiều vai trò, nhưng mỗi vai trò phải có một ranh giới và trách nhiệm pháp lý rõ ràng trong hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ed266bbc-e182-48d4-b157-acb6b472b6d0','07-phu-luc',NULL,1,'7.7 KHUNG TIÊU CHUẨN THẺ VAI TRÒ (ROLE CARD TEMPLATE)','77-khung-tieu-chuan-the-vai-tro-role-card-template',85,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a62f0276-4ae0-44e5-becd-67351eb70713','ed266bbc-e182-48d4-b157-acb6b472b6d0',145,'image',NULL,'book/07-phu-luc/57af1072-2c28-4be1-9190-c1c3bf91f0af-img21.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7c488fce-769d-4606-8592-2e7b7bfd0a37','07-phu-luc','ed266bbc-e182-48d4-b157-acb6b472b6d0',2,'BẢN ĐIỀU HÀNH THỰC TẾ: VAI TRÒ CONSULTANT (TƯ VẤN VIÊN)','ban-ieu-hanh-thuc-te-vai-tro-consultant-tu-van-vien',86,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('50ee2e02-f87e-4228-b5c0-23bc85702160','07-phu-luc','7c488fce-769d-4606-8592-2e7b7bfd0a37',3,'Thông tin chung','thong-tin-chung',87,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97db9ef2-c9be-408e-af65-ed2d580e1f32','50ee2e02-f87e-4228-b5c0-23bc85702160',146,'text','- **Tên Vai Trò:** Consultant (Tư vấn viên trực tiếp).  - **Circle Trực Thuộc:** Patient Circle (Vòng tròn Trải nghiệm & Chuyển đổi)().  - **Nhân Sự Nắm Giữ:** [Điền tên nhân sự thực tế tại phòng khám, ví dụ: Nguyễn Văn A].',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3edd944c-02aa-4013-8dc1-229bde1135f5','07-phu-luc','7c488fce-769d-4606-8592-2e7b7bfd0a37',3,'Purpose (Mục tiêu tối thượng)','purpose-muc-tieu-toi-thuong',88,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf0f5881-5142-42a3-8e1a-92578ade92f2','3edd944c-02aa-4013-8dc1-229bde1135f5',147,'text','- Thấu hiểu sâu sắc nhu cầu y khoa và tâm lý của bệnh nhân để thiết lập giải pháp điều trị toàn diện, tối ưu hóa tỷ lệ đồng ý điều trị (Case Acceptance Rate) trên nền tảng trung thực và trải nghiệm xuất sắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('36f81060-3cd1-45bb-b9dd-c7cc2a917a6a','07-phu-luc','7c488fce-769d-4606-8592-2e7b7bfd0a37',3,'Domain (Miền kiểm soát độc quyền)','domain-mien-kiem-soat-oc-quyen',89,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22c75a19-db8a-40e0-ba78-f9d6faa0eff6','36f81060-3cd1-45bb-b9dd-c7cc2a917a6a',148,'text','- Quy trình tương tác trực tiếp tại phòng tư vấn.  - Hạn mức ưu đãi/chiết khấu thương mại trong khung chính sách được duyệt().  - Dữ liệu lịch sử tư vấn cá nhân và trạng thái kế hoạch điều trị của khách hàng trên hệ thống CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('48f20b5f-f02d-46de-af51-5e556700ca0a','07-phu-luc','7c488fce-769d-4606-8592-2e7b7bfd0a37',3,'Accountabilities (Trách nhiệm giải trình)','accountabilities-trach-nhiem-giai-trinh',90,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f448f43-bae9-4e22-b46c-047716a5bf46','48f20b5f-f02d-46de-af51-5e556700ca0a',149,'text','- Tiếp nhận thông tin bàn giao bệnh nhân từ vai trò *Receptionist* theo đúng chuẩn SLA.  - Phối hợp với Bác sĩ lâm sàng tại ghế nha để dịch chuyển ngôn ngữ y khoa thành giải pháp dễ hiểu cho bệnh nhân.  - Xây dựng phương án tài chính, lộ trình thanh toán và chốt kế hoạch điều trị với khách hàng.  - Cập nhật 100% dữ liệu cuộc tư vấn, lý do đồng ý/từ chối và hình ảnh ca lâm sàng trực quan lên hệ thống CRM ngay sau khi kết thúc ca.  - Bàn giao thông tin chi tiết (Handover Notes) cho vai trò *Customer Care Specialist* đối với các ca đã chốt để kích hoạt quy trình chăm sóc hậu phẫu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7a859bfc-1838-413f-a819-53ef553a28f6','07-phu-luc','7c488fce-769d-4606-8592-2e7b7bfd0a37',3,'OMTM &amp; KPIs (Chỉ số đo lường hiệu suất)','omtm-amp-kpis-chi-so-o-luong-hieu-suat',91,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bcccc54-78a9-4ae7-8b1b-9bd7ff5fdfad','7a859bfc-1838-413f-a819-53ef553a28f6',150,'text','- **OMTM (One Metric That Matters - Chỉ số tối thượng):** Tỷ lệ đồng ý điều trị tổng (Case Acceptance Rate).  - **KPIs bổ trợ:**Giá trị đơn hàng trung bình (AOV) trên mỗi bệnh nhân.  - Tỷ lệ chốt các dịch vụ cốt lõi cao cấp (Implant, Niềng răng, Sứ thẩm mỹ).  - Tỷ lệ hoàn thành thanh toán đúng hạn đối với các ca trả góp/chia kỳ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('be07ade2-225e-4935-bce3-129b6daebbb0','07-phu-luc','7c488fce-769d-4606-8592-2e7b7bfd0a37',3,'Governance Note (Quy tắc giới hạn quyền hạn)','governance-note-quy-tac-gioi-han-quyen-han',92,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3b61c58-1c82-4381-9e2f-f0d0bce7deeb','be07ade2-225e-4935-bce3-129b6daebbb0',151,'text','- Được quyền chủ động quyết định giảm giá hoặc tặng quà cho bệnh nhân tối đa 5% giá trị gói điều trị nếu ca có tính chất thúc đẩy nhanh (nằm trong khung Policy hiện hành).  - Mọi trường hợp giảm giá vượt quá 5% hoặc yêu cầu tài trợ ca lâm sàng đặc biệt bắt buộc phải thực hiện quy trình leo thang hệ thống (Escalation) để xin Consent từ *Finance & Data Circle* hoặc *Core Circle*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd4e48ab-4a50-4bf8-aba4-e3a6835d6501','be07ade2-225e-4935-bce3-129b6daebbb0',152,'image',NULL,'book/07-phu-luc/3c0ba2f3-0897-4f22-b60f-f40b934d16a4-img22.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('85992ecf-865a-4338-8340-ac4d6a0a2349','07-phu-luc','ed266bbc-e182-48d4-b157-acb6b472b6d0',2,'HƯỚNG DẪN TRIỂN KHAI CHO FOUNDER','huong-dan-trien-khai-cho-founder',93,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('053af2af-a242-4995-b2ff-5378402f5bfd','85992ecf-865a-4338-8340-ac4d6a0a2349',153,'text','- **Gán người (Assigning):** In Thẻ vai trò này ra hoặc đóng gói trên hệ thống Notion/Lark. Khi giao việc, bạn không nói: *"Em làm tư vấn nha"*, mà nói: *"Gán em vào Vai trò Consultant của Patient Circle, chịu trách nhiệm giải trình toàn bộ các mục từ 1 đến 6"*.  - **Nguyên tắc kiêm nhiệm:** Nếu phòng khám quy mô nhỏ, một nhân sự có thể sở hữu đồng thời Thẻ vai trò *Consultant* và Thẻ vai trò *Tele-sales/Booking Specialist*. Khi khối lượng công việc phình to, bạn chỉ cần bóc Thẻ vai trò *Tele-sales* ra gán cho người mới, cấu trúc hệ thống hoàn toàn không bị xáo trộn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9aa30329-18c9-41d0-9993-b6fac7f372a5','07-phu-luc',NULL,1,'7.8 CẨM NANG VẬN HÀNH: CÔNG CỤ CỦA NGƯỜI ĐIỀU PHỐI (FACILITATOR)','78-cam-nang-van-hanh-cong-cu-cua-nguoi-ieu-phoi-facilitator',94,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c70a81ed-89be-4742-841a-7381eb101f06','9aa30329-18c9-41d0-9993-b6fac7f372a5',154,'text','Trong hệ điều hành **Dental Empire OS** (vận hành theo mô hình **S3 Holacracy Lite**), vai trò **Facilitator (Người điều phối)** không phải là một vị trí quản lý hay sếp ban lệnh. Facilitator là người giữ bản quyền quy trình họp, có trách nhiệm bảo vệ không gian tự chủ của Circle, giữ cho các cuộc thảo luận luôn đi đúng ngữ pháp hệ thống và triệt tiêu mọi biểu hiện của việc tranh luận cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('829d0e97-ffa7-466d-a830-5e940d4cdd52','9aa30329-18c9-41d0-9993-b6fac7f372a5',155,'text','Để thực thi vai trò này một cách hiệu quả, Facilitator bắt buộc phải sử dụng thành thạo **3 bộ công cụ vận hành** dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b45da6d4-8984-41aa-8f34-c71dc13fd616','07-phu-luc','9aa30329-18c9-41d0-9993-b6fac7f372a5',2,'CÔNG CỤ 1: KỊCH BẢN ĐIỀU PHỐI CUỘC HỌP TUẦN (WEEKLY TACTICAL AGENDA SCRIPT)','cong-cu-1-kich-ban-ieu-phoi-cuoc-hop-tuan-weekly-tactical-agenda-script',95,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4caa197-e670-4e5e-8120-ac1c22ab3b89','b45da6d4-8984-41aa-8f34-c71dc13fd616',156,'text','Cuộc họp Tactical hằng tuần tập trung hoàn toàn vào tiến độ công việc và tháo gỡ các thẻ điểm nghẽn (Tactical Tensions). Facilitator sử dụng kịch bản 6 bước sau để kiểm soát thời gian:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b8d2fea1-6d32-4515-b637-0c2b46669d93','07-phu-luc','b45da6d4-8984-41aa-8f34-c71dc13fd616',3,'Check-in (10 phút)','check-in-10-phut',96,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d0f6a47-fe8f-44fd-96f3-473f44b7557b','b8d2fea1-6d32-4515-b637-0c2b46669d93',157,'text','- **Hành động của Facilitator:** Yêu cầu từng thành viên chia sẻ nhanh trạng thái cảm xúc hiện tại hoặc một tiêu điểm cá nhân trước khi vào cuộc họp.- **Quy tắc:** Không thảo luận, không tranh luận. Mọi người chỉ lắng nghe và ghi nhận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bc6f41cf-c971-41be-b067-ba4e1b2daaef','07-phu-luc','b45da6d4-8984-41aa-8f34-c71dc13fd616',3,'Review Chỉ số &amp; Checklist (15 phút)','review-chi-so-amp-checklist-15-phut',97,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9eec831-c749-4ba4-9e6e-a56ede9dcf5e','bc6f41cf-c971-41be-b067-ba4e1b2daaef',158,'text','- **Hành động của Facilitator:** Yêu cầu các vai trò báo cáo nhanh các chỉ số cốt lõi (Metric review) hiển thị trên Dashboard.  - **Câu hỏi điều phối:** *"Chỉ số [X] của vai trò bạn tuần này đạt hay không đạt? Có điểm nghẽn nào phát sinh ngay từ chỉ số này không?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2ef14359-9cf3-426a-ba5b-d5531c8b7eeb','07-phu-luc','b45da6d4-8984-41aa-8f34-c71dc13fd616',3,'Cập nhật Dự án (10 phút)','cap-nhat-du-an-10-phut',98,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d6780e6-cbcd-4be5-872e-420117e7c847','2ef14359-9cf3-426a-ba5b-d5531c8b7eeb',159,'text','- **Hành động của Facilitator:** Đi qua danh sách các dự án đang chạy.  - **Câu hỏi điều phối:** *"Dự án [Y] có thay đổi trạng thái không? Có điểm nghẽn nào cần đưa vào mục xử lý không?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cafc81c9-8036-4a81-bc17-abdc41cf7eb7','07-phu-luc','b45da6d4-8984-41aa-8f34-c71dc13fd616',3,'Xây dựng Danh sách Điểm nghẽn (Triage Tensions - 5 phút)','xay-dung-danh-sach-iem-nghen-triage-tensions-5-phut',99,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c6ed672-406c-4c67-a37c-85a538a2691a','cafc81c9-8036-4a81-bc17-abdc41cf7eb7',160,'text','- **Hành động của Facilitator:** Yêu cầu các thành viên nêu tên các Tension (Điểm nghẽn) cần giải quyết và ghi nhanh thành các từ khóa lên bảng họp (hoặc file Notion/Lark).  - **Quy tắc:** Chỉ ghi nhận tên Tension, tuyệt đối không giải thích hay thảo luận ở bước này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('533bad88-4150-4656-941c-5a686d3bbe5a','07-phu-luc','b45da6d4-8984-41aa-8f34-c71dc13fd616',3,'Xử lý Điểm nghẽn (Triage - 45 phút)','xu-ly-iem-nghen-triage-45-phut',100,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15ae69cd-8bc3-4b36-9d6d-9679042c6627','533bad88-4150-4656-941c-5a686d3bbe5a',161,'text','- **Hành động của Facilitator:** Đi qua từng Tension đã ghi nhận. Gọi người sở hữu Tension lên lên tiếng.  - **Câu hỏi điều phối điều hướng:***"Bạn gặp nghẽn ở đâu? Bạn cần vai trò nào cung cấp thông tin hay hành động gì để giải quyết?"*- *"Đề xuất hành động tiếp theo (Next-action) của bạn là gì?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9d3c4a51-ba9b-473a-8f77-6f5e1d95165e','07-phu-luc','b45da6d4-8984-41aa-8f34-c71dc13fd616',3,'Check-out (5 phút)','check-out-5-phut',101,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73a24f15-af5a-458d-b14f-ae299e106a57','9d3c4a51-ba9b-473a-8f77-6f5e1d95165e',162,'text','- **Hành động của Facilitator:** Đóng cuộc họp và yêu cầu mọi người đánh giá nhanh hiệu quả của buổi họp hôm nay.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7bb337ff-c194-4a6e-8be0-c98dd5bf9a88','07-phu-luc','9aa30329-18c9-41d0-9993-b6fac7f372a5',2,'CÔNG CỤ 2: QUY TRÌNH MÀNG LỌC "PHẢN ĐỐI HỢP LỆ" (OBJECTION TEST STEP-BY-STEP)','cong-cu-2-quy-trinh-mang-loc-phan-oi-hop-le-objection-test-step-by-step',102,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ee574d5-156c-415f-8712-1634ff589f31','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',163,'text','Công cụ này được Facilitator kích hoạt trong các cuộc họp **Monthly Governance** khi có một đề xuất (Proposal) thay đổi quy trình hoặc chính sách mới bị một thành viên phản đối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('983d82fd-0f57-46e5-879f-a8f42ad7a3e2','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',164,'text','**Khi có ý kiến phản đối -> Facilitator thực hiện kiểm tra qua 3 câu hỏi lọc:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f36e003-779d-4c7b-bfb9-87255f5fa3d0','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',165,'text','- **Câu hỏi 1 (Kiểm tra Bằng chứng):** *"Bạn có dữ liệu lịch sử hoặc bằng chứng cụ thể nào cho thấy đề xuất này chắc chắn sẽ gây thiệt hại cho phòng khám không? Hay đây là suy đoán?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a61b06e-ad79-41c3-87b1-b3b4e1bf1c6b','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',166,'text','*-> Nếu là suy đoán:* Khóa phản đối, đề xuất tiếp tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0945af81-f377-40ab-ad07-51291f5b558b','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',167,'text','- **Câu hỏi 2 (Kiểm tra Mục tiêu):** *"Đề xuất này có vi phạm hoặc cản trở trực tiếp việc thực hiện Purpose (Mục tiêu tối thượng) của Circle này hay của vai trò bạn đang nắm giữ không?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd1d7e5a-38d5-4322-8b33-9489af008148','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',168,'text','*-> Nếu không cản trở:* Khóa phản đối, đề xuất tiếp tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a0c571b-e0ba-4b46-8bb1-207892dc8f31','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',169,'text','- **Câu hỏi 3 (Kiểm tra Tính an toàn):** *"Đề xuất này có thực sự ''không an toàn để thử'' không? Nếu chúng ta chỉ giới hạn áp dụng quy trình này trong vòng 2 tuần để thu thập dữ liệu thực tế, nó có gây ra hậu quả nào không thể sửa chữa được không?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04b8e8e1-244a-4fae-8938-0412f5e539ab','7bb337ff-c194-4a6e-8be0-c98dd5bf9a88',170,'text','*-> Nếu sửa sai được:* Khóa phản đối, đề xuất tiếp tục thực thi thử nghiệm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b5a18b80-5d62-47c5-87e8-96cadc6e9ba9','07-phu-luc','9aa30329-18c9-41d0-9993-b6fac7f372a5',2,'CÔNG CỤ 3: BỘ KHUNG "NẮN DÒNG TENSION" (TRIAGE TENSIONS CHECKLIST)','cong-cu-3-bo-khung-nan-dong-tension-triage-tensions-checklist',103,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50ccf398-c850-4807-ba2c-d7804c8e902b','b5a18b80-5d62-47c5-87e8-96cadc6e9ba9',171,'text','Nhân sự chưa quen với mô hình tự chủ thường có xu hướng biến các buổi họp thành nơi than vãn, kể lể hoặc tấn công cá nhân. Khi một thành viên bắt đầu nói lan man, Facilitator phải sử dụng kỹ thuật **Nắn dòng Tension** bằng cách ngắt lời một cách văn minh và yêu cầu họ làm rõ qua 3 bước:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f978c7f5-2f0a-40f8-b421-43c939f36a26','b5a18b80-5d62-47c5-87e8-96cadc6e9ba9',172,'text','📐 **Khung định vị Tension của Facilitator:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d12fc128-e981-4729-80ef-a2adfabe2232','b5a18b80-5d62-47c5-87e8-96cadc6e9ba9',173,'text','- **"Hiện tại thực tế là gì?"** (Yêu cầu chỉ nói về thực trạng, không phán xét).  - **"Trạng thái lý tưởng bạn muốn là gì?"** (Yêu cầu nói về mong muốn phục vụ công việc).  - **"Bạn cần vai trò nào hỗ trợ việc gì?"** (Ép người nói phải đưa ra yêu cầu cụ thể cho một vai trò, thay vì nói chung chung).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a963c5a2-fa5f-484e-9e20-005250a84d0b','b5a18b80-5d62-47c5-87e8-96cadc6e9ba9',174,'text','Các câu nói cửa miệng (SLA Scripts) dành cho Facilitator:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5bacea07-df5e-4ece-b60f-c936efb7224f','b5a18b80-5d62-47c5-87e8-96cadc6e9ba9',175,'text','- *"Cảm ơn góc nhìn của bạn, nhưng hãy cho biết việc này đang ảnh hưởng trực tiếp đến Vai trò nào của bạn?*- *"Chúng ta không bàn chuyện đúng sai ở đây. Đề xuất cụ thể của bạn để giải quyết điểm nghẽn này là gì?"*- *"Việc này có nằm trong Domain của bạn không? Nếu có, bạn hoàn toàn tự quyết mà không cần đưa vào buổi họp hôm nay."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cfca0f38-262f-44d8-95ce-b2b1f4ae7a54','07-phu-luc','9aa30329-18c9-41d0-9993-b6fac7f372a5',2,'CÁC ĐIỀU CẤM KỴ ĐỐI VỚI VAI TRÒ FACILITATOR','cac-ieu-cam-ky-oi-voi-vai-tro-facilitator',104,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dea34517-efd3-42ca-be51-cbd2dc1129cf','cfca0f38-262f-44d8-95ce-b2b1f4ae7a54',176,'text','- **Không tự ý đưa ra quyết định thay cho người khác:** Facilitator chỉ điều phối quy trình họp, tuyệt đối không được dùng quyền điều phối để ép buộc các vai trò khác phải làm theo ý mình.  - **Không tham gia thảo luận khi đang điều phối:** Nếu Facilitator muốn phát biểu ý kiến dưới góc độ một vai trò chuyên môn mà mình đang kiêm nhiệm, họ phải tuyên bố: *"Bây giờ tôi xin thoát vai điều phối trong 1 phút để nói dưới vai trò [Tên vai trò chuyên môn]"*. Sau khi nói xong phải tuyên bố: *"Tôi quay trở lại vai trò Facilitator"*.- **Không để cuộc họp quá giờ:** Bảo vệ nghiêm ngặt thời gian (Time-boxing) của từng phần trong Agenda để xây dựng tính kỷ luật cho đội ngũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e23f708d-4290-4ac2-bbb0-22a0f1b3a95d','07-phu-luc',NULL,1,'7.9 THẺ VAI TRÒ ĐỀ XUẤT','79-the-vai-tro-e-xuat',105,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b951aade-fce1-4ec3-82c2-485afdaf8614','e23f708d-4290-4ac2-bbb0-22a0f1b3a95d',177,'text','Hệ thống được chia làm hai nhóm chính: **Vai trò Cấu trúc** (Bắt buộc phải có ở tất cả các Circle để vận hành cơ chế họp, quản trị) và **Vai trò Vận hành chuyên môn**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('55344808-c1c2-4acc-b109-50dc685a1402','07-phu-luc','e23f708d-4290-4ac2-bbb0-22a0f1b3a95d',2,'NHÓM 1: CÁC VAI TRÒ CẤU TRÚC (STRUCTURAL ROLES)','nhom-1-cac-vai-tro-cau-truc-structural-roles',106,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee437fbd-40e2-4506-b841-a89798fe3920','55344808-c1c2-4acc-b109-50dc685a1402',178,'image',NULL,'book/07-phu-luc/f06b49ae-a1fd-4714-8c23-4f48c85ec462-img23.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('19b56a02-9db7-4a46-9d0b-88d6af2cfb8b','55344808-c1c2-4acc-b109-50dc685a1402',179,'text','Bắt buộc phải có mặt và được bầu chọn/chỉ định tại tất cả các Circle con để duy trì ngữ pháp hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9777a28-9c96-4fd9-b4db-08244216d431','55344808-c1c2-4acc-b109-50dc685a1402',180,'text','- **Circle Lead (Đầu mối điều phối xuống):***Mục tiêu:* Đảm bảo Circle thực hiện đúng chiến lược từ Core Circle giao xuống, phân bổ nguồn lực/nhân sự nội bộ và chịu trách nhiệm cao nhất về hiệu suất tổng của Circle.  - **Rep Link (Đầu mối đại diện lên):***Mục tiêu:* Đại diện cho tiếng nói và quyền lợi của các thành viên trong Circle con; trực tiếp mang các điểm nghẽn (Tensions) hoặc đề xuất vượt cấp lên Circle mẹ xử lý.  - **Facilitator (Người điều phối cuộc họp):***Mục tiêu:* Điều phối các nhịp họp hằng tuần/tháng (Tactical & Governance) đi đúng thời gian và đúng quy trình màng lọc phản đối (Objection Test).  - **Secretary (Thư ký Circle):***Mục tiêu:* Quản trị và cập nhật thời gian thực hồ sơ phân quyền, các chính sách (Policy) mới của Circle vào hệ thống **Governance Logbook**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('841e1055-88aa-44a5-b563-6d982bfbc9ff','07-phu-luc','e23f708d-4290-4ac2-bbb0-22a0f1b3a95d',2,'NHÓM 2: CÁC VAI TRÒ VẬN HÀNH CHUYÊN MÔN (OPERATIONAL ROLES)','nhom-2-cac-vai-tro-van-hanh-chuyen-mon-operational-roles',107,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('656b91bd-7133-457f-bc80-3dbdb23807a0','07-phu-luc','841e1055-88aa-44a5-b563-6d982bfbc9ff',3,'Core Circle (Vòng tròn Trung tâm / Ban Chiến lược)','core-circle-vong-tron-trung-tam-ban-chien-luoc',108,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('177ddf6e-c536-47c2-85b4-e25c7a9de4ab','656b91bd-7133-457f-bc80-3dbdb23807a0',181,'text','- **CEO / Founder (Tổng điều phối hệ thống):***Mục tiêu:* Bảo vệ bản sắc cốt lõi (Root), lõi văn hóa SKY, phê duyệt kiến trúc hệ thống và phân bổ hạn mức tài nguyên chiến lược.  - *KPI cốt lõi:* Biên lợi nhuận ròng toàn hệ thống, Giá trị thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('918ec293-b3fc-4217-9c95-c8dad41fd4da','07-phu-luc','841e1055-88aa-44a5-b563-6d982bfbc9ff',3,'Growth Circle (Vòng tròn Tăng trưởng - Thu hút Đầu phễu)','growth-circle-vong-tron-tang-truong-thu-hut-au-pheu',109,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05e9d7a6-1ba7-4b8d-aaa9-f89298b2cb6f','918ec293-b3fc-4217-9c95-c8dad41fd4da',182,'text','- **Marketing Manager (Circle Lead):***Mục tiêu:* Điều phối và tối ưu hóa chi phí của toàn bộ các chiến dịch truyền thông thu hút lead().  - *KPI cốt lõi:* Tỷ lệ hoàn thành mục tiêu số lượng Lead hằng tháng.  - **Media Specialist (Chuyên viên Mạng lưới truyền thông):***Mục tiêu:* Vận hành và duy trì sự ổn định của hệ thống kênh Media Network công cộng của phòng khám.  - *KPI cốt lõi:* Lượng tương tác tự nhiên (Reach/Views), Số lượng Lead tự nhiên.  - **Ads Optimizer (Chuyên viên Tối ưu quảng cáo):***Mục tiêu:* Phân bổ ngân sách quảng cáo số hiệu quả để mang về dữ liệu khách hàng chất lượng với chi phí tối ưu.  - *KPI cốt lõi:* Chi phí trên một Lead (CPL).  - **Content Creator (Chuyên viên Sản xuất nội dung):***Mục tiêu:* Đóng gói kiến thức y khoa, hình ảnh ca lâm sàng thành các nội dung số có tính giáo dục và xây dựng tài sản uy tín (Trust Assets).  - *KPI cốt lõi:* Tỷ lệ chuyển đổi nội dung (Click-to-Lead Rate).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d5691b83-5de1-4539-ad23-0cf958b4811c','07-phu-luc','841e1055-88aa-44a5-b563-6d982bfbc9ff',3,'Patient Circle (Vòng tròn Trải nghiệm &amp; Chuyển đổi Khách hàng)','patient-circle-vong-tron-trai-nghiem-amp-chuyen-oi-khach-hang',110,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d7b2dfb-00c3-4ace-9155-edd3bda9c0d4','d5691b83-5de1-4539-ad23-0cf958b4811c',183,'text','- **Clinic Manager (Circle Lead):***Mục tiêu:* Đảm bảo tính liên tục của phễu chuyển đổi tại chỗ và chất lượng điểm chạm không gian trực tiếp.  - *KPI cốt lõi:* Tổng doanh thu thực thu phòng khám.  - **Tele-sales / Booking Specialist (Chuyên viên Đặt lịch):***Mục tiêu:* Khai thác dữ liệu lead đổ về để tối ưu hóa tỷ lệ chuyển đổi sang lịch hẹn thành công().  - *KPI cốt lõi:* Tỷ lệ đặt hẹn thành công (Lead-to-Book Rate).  - **Receptionist (Lễ tân phòng khám):***Mục tiêu:* Đón tiếp trực tiếp, làm thủ tục check-in check-out chuyên nghiệp và tối ưu tỷ lệ khách thực tế đến khám.  - *KPI cốt lõi:* Tỷ lệ khách đến khám thực tế (Show-up Rate).  - **Consultant (Tư vấn viên trực tiếp):***Mục tiêu:* Thấu hiểu nhu cầu và xây dựng phương án tài chính giúp khách hàng đồng ý thực hiện kế hoạch điều trị.  - *KPI cốt lõi:* Tỷ lệ đồng ý điều trị tổng (Case Acceptance Rate), Giá trị đơn hàng trung bình (AOV).  - **Customer Care Specialist (Chuyên viên Chăm sóc khách hàng):***Mục tiêu:* Theo dõi sát sao hậu phẫu, nhắc lịch tái khám định kỳ, thu thập đánh giá và kích hoạt hệ sinh thái giới thiệu khách hàng (Referral).  - *KPI cốt lõi:* Điểm số hài lòng giới thiệu (NPS), Tỷ lệ khách quay lại (Retention Rate).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('963493da-2dec-4392-b9c8-9966cf705e2d','07-phu-luc','841e1055-88aa-44a5-b563-6d982bfbc9ff',3,'Clinical Circle (Vòng tròn Chuyên môn Lâm sàng)','clinical-circle-vong-tron-chuyen-mon-lam-sang',111,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c66fdac7-d1a5-4951-8f1b-e25e7a809f1a','963493da-2dec-4392-b9c8-9966cf705e2d',184,'text','- **Bác sĩ trưởng (Circle Lead):***Mục tiêu:* Kiểm soát chất lượng điều trị toàn diện, đảm bảo an toàn y khoa tối cao và phân bổ ca điều trị hợp lý().  - *KPI cốt lõi:* Tỷ lệ ca điều trị an toàn tuyệt đối (0% tai biến).  - **Bác sĩ điều trị chuyên sâu (Implant / Chỉnh nha / Thẩm mỹ):***Mục tiêu:* Thực thi kỹ thuật lâm sàng chuẩn xác, mang lại kết quả điều trị xuất sắc cho bệnh nhân.  - *KPI cốt lõi:* Tỷ lệ hoàn thành ca đúng lộ trình, Tỷ lệ chốt thêm giải pháp toàn diện tại ghế.  - **Điều dưỡng trưởng (Quản lý Phụ tá & Vô trùng):***Mục tiêu:* Điều phối nhân lực phụ tá, kiểm soát nghiêm ngặt quy trình vô khuẩn khép kín và quản lý kho vật liệu tiêu hao.  - *KPI cốt lõi:* Tỷ lệ tuân thủ SOP vô khuẩn (100%), Hiệu suất sử dụng ghế nha (Chair Utilization Rate).  - **Phụ tá nha khoa (Dental Assistant):***Mục tiêu:* Hỗ trợ Bác sĩ tại ghế nha theo đúng quy trình bốn tay, chuẩn bị phòng máy chu đáo trước ca khám.  - *KPI cốt lõi:* Tỷ lệ chuẩn bị dụng cụ chính xác theo checklist.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('74253511-41e6-4d30-ae4d-b538c356e151','07-phu-luc','841e1055-88aa-44a5-b563-6d982bfbc9ff',3,'Finance &amp; Data Circle (Vòng tròn Tài chính &amp; Dữ liệu)','finance-amp-data-circle-vong-tron-tai-chinh-amp-du-lieu',112,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53feb1ca-4786-4a34-a1d5-feecc1507a0a','74253511-41e6-4d30-ae4d-b538c356e151',185,'text','- **Kế toán trưởng (Circle Lead):***Mục tiêu:* Bảo vệ an toàn dòng tiền, kiểm soát định mức chi phí và tối ưu hóa cấu trúc lợi nhuận phòng khám.  - *KPI cốt lõi:* Dòng tiền tự do (Free Cash Flow), Tỷ lệ chi phí vận hành (OPEX Rate).  - **Thu ngân / Thủ quỹ phòng khám:***Mục tiêu:* Thực hiện quy trình thu tiền, xuất hóa đơn minh bạch và đối soát chốt sổ quỹ tiền mặt/ngân hàng hằng ngày.  - *KPI cốt lõi:* Độ chính xác đối soát dòng tiền cuối ngày (100%).  - **Data Analyst (Chuyên viên Phân tích dữ liệu):***Mục tiêu:* Tổng hợp chỉ số từ tất cả các Circle để duy trì tính chính xác của hệ thống báo cáo Real-time Dashboard (One Light).  - *KPI cốt lõi:* Tốc độ và độ chính xác của số liệu cập nhật trên Dashboard.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0301b3b5-4439-4df6-9dc1-4fbcc6629cdb','07-phu-luc','841e1055-88aa-44a5-b563-6d982bfbc9ff',3,'People &amp; Culture Circle (Vòng tròn Con người &amp; Văn hóa)','people-amp-culture-circle-vong-tron-con-nguoi-amp-van-hoa',113,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b250a164-cce8-4c63-af14-4cc8e7d28308','0301b3b5-4439-4df6-9dc1-4fbcc6629cdb',186,'text','- **Trưởng phòng Nhân sự (Circle Lead):***Mục tiêu:* Hoạch định nguồn nhân lực, quản trị khung năng lực S.T.A.R.S và duy trì chỉ số gắn kết nội bộ.  - *KPI cốt lõi:* Tỷ lệ giữ chân nhân sự (Staff Retention Rate).  - **Recruiter (Chuyên viên Tuyển dụng):***Mục tiêu:* Săn tìm và thu hút nhân tài có bộ mã gen phù hợp với tiêu chuẩn văn hóa và năng lực của phòng khám.  - *KPI cốt lõi:* Tỷ lệ hoàn thành kế hoạch tuyển dụng đúng hạn.  - **Trainer (Chuyên viên Đào tạo SOP):***Mục tiêu:* Tổ chức đào tạo, kiểm tra và đảm bảo 100% nhân sự mới/cũ đều thấu hiểu và thực thi chuẩn xác các bộ SOP.  - *KPI cốt lõi:* Tỷ lệ nhân sự đạt sát hạch quy trình SOP nội bộ.  - **Culture Coordinator (Chuyên viên Điều phối văn hóa):***Mục tiêu:* Lan tỏa giá trị cốt lõi TO BE SKY vào hành vi hằng ngày của nhân sự, tổ chức các hoạt động truyền thông nội bộ kết nối hệ thống.  - *KPI cốt lõi:* Chỉ số đo lường mức độ hạnh phúc và hài lòng nội bộ (eNPS).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8aef24b8-3e06-414b-bb28-b8d4d3b16c41','07-phu-luc',NULL,1,'7.10 PLAYBOOK: NHỊP HỌP ĐỊNH KỲ (MEETING RHYTHM) TRONG PHÒNG KHÁM','710-playbook-nhip-hop-inh-ky-meeting-rhythm-trong-phong-kham',114,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d9396010-1a96-41b5-a592-bd5b59c0a84a','8aef24b8-3e06-414b-bb28-b8d4d3b16c41',187,'text','Nếu ranh giới Domain là xương sống, Thẻ vai trò là cơ bắp, thì **Nhịp họp Định kỳ** chính là hệ tuần hoàn bơm máu và oxy (thông tin và quyết định) đi nuôi dưỡng toàn bộ cơ thể phòng khám(). Hệ điều hành `Dental Empire OS` thiết lập 4 nhịp đập cố định, tách biệt hoàn toàn giữa "Vận hành thực thi" (Tactical) và "Sửa đổi cấu trúc" (Governance).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c6ec9af9-7fa0-424b-b852-70713bb0d70a','07-phu-luc','8aef24b8-3e06-414b-bb28-b8d4d3b16c41',2,'Daily Huddle - Nhịp Đập Hằng Ngày (15 Phút)','daily-huddle-nhip-ap-hang-ngay-15-phut',115,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85646023-e6d9-42f3-9d3d-ec624cc7fbe4','c6ec9af9-7fa0-424b-b852-70713bb0d70a',188,'text','*Kích hoạt năng lượng đầu ngày và xử lý nhanh các điểm nghẽn tức thì.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b56b6bf9-65ca-4222-a960-486686dc9ce2','c6ec9af9-7fa0-424b-b852-70713bb0d70a',189,'text','- **Thời gian & Hình thức:** **15 phút** đầu giờ sáng, toàn bộ thành viên đứng họp trực tiếp hoặc online.  - **Người điều phối:** *Circle Lead* hoặc luân phiên giữa các vai trò trong Circle.  - **Nội dung cốt lõi:** Từng vai trò lần lượt trả lời nhanh 3 câu hỏi (Quy tắc 60 giây/người):  *Hôm qua tôi đã hoàn thành việc gì quan trọng phục vụ Purpose của Circle?*- *Hôm nay tiêu điểm hành động cốt lõi của tôi là gì?*- *Tôi đang gặp điểm nghẽn (Tension) nào cần vai trò nào hỗ trợ tháo gỡ ngay không?*- **Đầu ra (Output):** Các vai trò nắm bắt được lịch làm việc chéo của nhau, giải tỏa nhanh các nút thắt sự vụ phát sinh trong ngày.  - *Lưu ý nghiêm ngặt:* Không sa đà vào phân tích giải quyết vấn đề. Nếu có vấn đề phát sinh phức tạp, điều phối viên ghi nhận và yêu cầu hai vai trò liên quan tự ngồi lại sau cuộc họp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b6f940b-0b9f-43a6-bda7-8088ab4098ec','c6ec9af9-7fa0-424b-b852-70713bb0d70a',190,'image',NULL,'book/07-phu-luc/5e053b5a-abc7-4b84-abb4-52127109a2dc-img24.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('78f43d55-7946-4ec3-8ab1-eb7911ca1c45','07-phu-luc','8aef24b8-3e06-414b-bb28-b8d4d3b16c41',2,'Weekly Tactical Meeting - Vận Hành Hằng Tuần (60 - 90 Phút)','weekly-tactical-meeting-van-hanh-hang-tuan-60-90-phut',116,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('803f0b34-6e01-447a-913a-739680068d2d','78f43d55-7946-4ec3-8ab1-eb7911ca1c45',191,'text','*Đồng bộ tiến độ dự án, cập nhật chỉ số Dashboard và giải quyết các thẻ công việc phát sinh.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4323786c-5957-4a6d-9a35-a8d47d720005','78f43d55-7946-4ec3-8ab1-eb7911ca1c45',192,'text','- **Thời gian & Tần suất:** **60 - 90 phút**, cố định vào một ngày đầu tuần (ví dụ: Thứ Hai).  - **Người điều phối:** *Facilitator* điều hành, *Secretary* ghi chép.  - **Chương trình nghị sự chuẩn (Agenda):****Bước 1: Check-in (10 phút):** Chia sẻ trạng thái để tập trung vào cuộc họp.  - **Bước 2: Review Chỉ số (15 phút):** Đi qua các chỉ số OMTM/KPI của từng vai trò trên Dashboard số (One Light). Chỉ báo cáo Đạt hoặc Không Đạt, không giải trình lý do.  - **Bước 3: Cập nhật Dự án (10 phút):** Rà soát danh sách các đầu việc lớn đang chạy của Circle.  - **Bước 4: Triage Tensions (45 phút):** Liệt kê các điểm nghẽn thực tế phát sinh trong tuần(). Giải quyết từng thẻ một bằng cách đặt câu hỏi: *"Bạn cần hành động cụ thể nào hoặc thông tin gì từ vai trò nào để thông nghẽn?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd308cc4-f02e-48bc-b51d-8271f85e74b9','78f43d55-7946-4ec3-8ab1-eb7911ca1c45',193,'image',NULL,'book/07-phu-luc/0e0546a2-bd1b-40d5-a591-d25ee0703d53-img25.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('482c8ff3-dd7b-418c-805e-d18f76f6deeb','07-phu-luc','8aef24b8-3e06-414b-bb28-b8d4d3b16c41',2,'Monthly Governance Meeting - Quản Trị Cấu Trúc (60 - 90 Phút)','monthly-governance-meeting-quan-tri-cau-truc-60-90-phut',117,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f8ba3d2-b076-463c-a40c-8a09d8860d69','482c8ff3-dd7b-418c-805e-d18f76f6deeb',194,'text','*Sửa đổi bộ máy, tinh chỉnh biên giới quyền hạn dựa trên điểm nghẽn tích lũy. Không bàn chuyện thực thi sự vụ tại đây.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8678bb03-b274-4392-93f5-c050f4c0a2bc','482c8ff3-dd7b-418c-805e-d18f76f6deeb',195,'text','- **Thời gian & Tần suất:** **60 - 90 phút**, định kỳ 1 tháng/lần.  - **Người điều phối:** *Facilitator* điều hành bắt buộc theo màng lọc **Objection Test**.  - **Nội dung cốt lõi:**Tạo mới, xóa bỏ hoặc chỉnh sửa các Vai trò (Roles) trong Circle.  - Điều chỉnh hoặc bổ sung Trách nhiệm giải trình (Accountabilities) cho một Vai trò để bám sát thực tế.  - Ban hành hoặc sửa đổi các quy tắc biên giới (Policy) bên trong Circle.  - Bầu chọn nhân sự nắm giữ các vai trò cấu trúc (*Facilitator, Secretary, Rep Link*).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc546661-a2d0-4f2b-8373-543c9f219b4a','482c8ff3-dd7b-418c-805e-d18f76f6deeb',196,'image',NULL,'book/07-phu-luc/212adabb-b22d-434c-b27c-8e71eec63f80-img26.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('85dcc0fe-840f-474d-8358-47d169aae258','07-phu-luc','8aef24b8-3e06-414b-bb28-b8d4d3b16c41',2,'Monthly S.T.A.R.S Review - Kiểm Toán Chiến Lược (120 Phút)','monthly-stars-review-kiem-toan-chien-luoc-120-phut',118,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5a004ef0-487a-485b-a39e-fd3b83521227','85dcc0fe-840f-474d-8358-47d169aae258',197,'text','*Kiểm tra sức khỏe toàn diện của Circle, đánh giá độ lệch mục tiêu và thiết kế Sprint hành động 90 ngày.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82b62f63-b737-4c01-9490-5b92cfe23490','85dcc0fe-840f-474d-8358-47d169aae258',198,'text','- **Thời gian & Tần suất:** **120 phút**, diễn ra vào tuần đầu tiên của tháng mới().  - **Thành phần tham gia:** Toàn bộ thành viên trong Circle cùng đại diện từ *Finance & Data Circle*.  - **Nội dung kiểm toán 5 cánh S.T.A.R.S:****S (Strategy):** Mục tiêu doanh thu (ví dụ: **1.2 tỷ**) và các tỷ lệ chuyển đổi tháng trước lệch bao nhiêu % so với thực tế?- **T (Team):** Cơ chế thưởng KPI Circle tháng qua có tạo động lực đúng không? Có vai trò nào bị quá tải cấu trúc không?  - **A (Acquisition):** Chi phí trên Lead (CPL) và chi phí có một khách hàng (CPA) có nằm trong định mức an toàn không? - **R (Revenue):** Điểm nghẽn lớn nhất trong hành trình dòng chảy khách hàng (Funnel) tháng qua nằm ở bước nào?- **S (System/Satisfaction):** Điểm NPS của phòng khám biến động ra sao? Tỷ lệ tuân thủ SOP của nhân sự đạt bao nhiêu %?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56d296ae-6ed4-4ca5-87a5-4d62b3823f74','85dcc0fe-840f-474d-8358-47d169aae258',199,'image',NULL,'book/07-phu-luc/cf0015aa-75c0-4209-b34a-fac70f6e0e70-img27.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('84073de4-4295-4d3b-899e-18dec9cf2839','07-phu-luc','8aef24b8-3e06-414b-bb28-b8d4d3b16c41',2,'Cơ chế chuyển hóa áp lực (Tensions) thành cải tiến:','co-che-chuyen-hoa-ap-luc-tensions-thanh-cai-tien',119,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4e2bb06-860e-4a98-8744-d7fa40417ebe','84073de4-4295-4d3b-899e-18dec9cf2839',200,'image',NULL,'book/07-phu-luc/362d4247-2451-4c46-91d3-1089e2d65748-img28.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('faa0bd46-4cbc-4a37-823a-3b6f7f0b317b','07-phu-luc',NULL,1,'7.11 KẾT CHƯƠNG: EMPIRE CIRCLE - TỪ ĐIỀU HÀNH CÁ NHÂN SANG HỆ THỐNG TỰ THÍCH NGHI','711-ket-chuong-empire-circle-tu-ieu-hanh-ca-nhan-sang-he-thong-tu-thich-nghi',120,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61100521-c763-4d2f-bb9b-90060ae9fb7e','faa0bd46-4cbc-4a37-823a-3b6f7f0b317b',201,'text','**Lời kết chương:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a4a7163-0a31-40ef-bf9d-ad3f15be1b59','faa0bd46-4cbc-4a37-823a-3b6f7f0b317b',202,'text','Bản chất của mô hình Empire Circle không phải là loại bỏ vai trò của người lãnh đạo, mà là định vị lại nó. Thay vì làm một nhà quản lý bận rộn giải quyết các sự vụ vụn vặt hằng ngày, cấu trúc này giải phóng Founder để trở thành một kiến trúc sư trưởng, tập trung bảo vệ bản sắc cốt lõi (Roots) và kiến tạo "bầu trời" (SKY) cho đội ngũ tự chủ thực thi dưới một nguồn sáng dữ liệu minh bạch (One Light).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('65008545-0948-4ad2-a78c-feae77444608','07-phu-luc','faa0bd46-4cbc-4a37-823a-3b6f7f0b317b',2,'Ba thay đổi tư duy mang tính quyết định','ba-thay-oi-tu-duy-mang-tinh-quyet-inh',121,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e31a1b8d-0610-4134-b34d-4c447fa42493','65008545-0948-4ad2-a78c-feae77444608',203,'image',NULL,'book/07-phu-luc/7a0bd0a8-3385-4b8d-be53-2838cf85353e-img29.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d77ea9e-2860-4ef8-8a12-6bf8cee5bec1','65008545-0948-4ad2-a78c-feae77444608',204,'text','- **Tách biệt Con người (Soul) và Công việc (Role):** Nhân sự không bị đóng đinh vào một chức danh xơ cứng. Một cá nhân có thể nắm giữ nhiều thẻ vai trò (Role Cards) khác nhau dựa trên năng lực thực tế, giúp tối ưu hóa tối đa nguồn lực nội tại của phòng khám.- **Quyền hạn đi liền với Biên giới:** Không còn những cuộc tranh luận đùn đẩy trách nhiệm. Ranh giới giữa năm khối Circle chuyên môn (Growth, Patient, Clinical, Finance & Data, People & Culture) đã được phân định bằng các Miền kiểm soát độc quyền (Domain) và các điểm bàn giao (Handover Funnel) có cam kết thời gian (SLA) chặt chẽ.- **Tiến hóa dựa trên Xung đột thực tế:** Hệ thống không thay đổi cấu trúc dựa trên các giả định lý thuyết suông. Mọi sự tinh chỉnh, ban hành chính sách (Policy) hay tách/gộp vai trò trong Sổ tay quản trị (Governance Logbook) đều phải bắt nguồn từ các điểm nghẽn (Tensions) phát sinh từ thực tế lâm sàng và vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5749e173-21bf-483a-abfa-f93b879c45db','07-phu-luc','faa0bd46-4cbc-4a37-823a-3b6f7f0b317b',2,'Bộ công cụ thực thi cốt lõi','bo-cong-cu-thuc-thi-cot-loi',122,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('abe18b2d-be50-478d-b742-8cc5f7e48f44','5749e173-21bf-483a-abfa-f93b879c45db',205,'image',NULL,'book/07-phu-luc/0121c5d6-d94d-41b8-990c-0af4d960acbc-img30.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('83eef155-5aac-4798-940c-844da3e95153','5749e173-21bf-483a-abfa-f93b879c45db',206,'text','Để chương "Empire Circle" này thực sự đi vào đời sống vận hành của phòng khám, đội ngũ quản lý bắt buộc phải nhuần nhuyễn bộ ba công cụ điều hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d2b64f7d-d624-4005-b5b3-1db7dfa53e2f','5749e173-21bf-483a-abfa-f93b879c45db',207,'text','- **Quy trình màng lọc Phản đối (Objection Test):** Công cụ của Người điều phối (Facilitator) nhằm triệt tiêu các tranh luận cảm tính, bảo vệ triết lý tối cao *"Đủ an toàn để thử, đủ tốt để tiến lên" (Safe to try, Enough to move on)*.- **Hệ thống Thẻ Vai Trò (Role Cards):** Định nghĩa tường minh về Mục tiêu (Purpose) và Trách nhiệm giải trình (Accountability) của từng vị trí, liên kết trực tiếp với mô hình năng lực và hiệu suất.- **Nhịp họp Định kỳ (Meeting Rhythm):** Duy trì "nhịp tim" đồng bộ cho phòng khám, từ cuộc họp nhanh Daily Huddle 15 phút, họp giải quyết thẻ công việc Weekly Tactical, cho đến buổi kiểm toán chiến lược Monthly S.T.A.R.S Review hằng tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('307711bb-eb83-44d9-a9a3-7e3fb7bd49e4','5749e173-21bf-483a-abfa-f93b879c45db',208,'text','Khép lại chương này, phòng khám của bạn đã chính thức loại bỏ được mô hình quản trị kim tự tháp xơ cứng để sở hữu một **Kiến trúc thượng tầng phẳng, nhất quán và có khả năng tự thích nghi hữu cơ**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a66b3654-6dec-464a-bc6d-794d2655353a','5749e173-21bf-483a-abfa-f93b879c45db',209,'text','Quyền lực điều hành đã được phân rã từ một cá nhân Founder sang hệ thống các Vòng tròn tự chủ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3fa5f6ef-9f9a-497f-ab77-a6fac6a59b6c','5749e173-21bf-483a-abfa-f93b879c45db',210,'text','Phòng khám đã sẵn sàng vận hành tự động, minh bạch dưới một nguồn sáng dữ liệu và bám sát lộ trình tăng trưởng bền vững của tổ chức.',NULL,NULL,NULL,NULL,NULL);
